use agent_runtime::agent::AgentHandle;
use agent_runtime::orchestrator::{Task, TaskPriority, TaskResult};
use agent_runtime::registry::AgentRegistry;
use agnos_common::{AgentConfig, AgentId, AgentStatus, AgentType, ResourceLimits, SandboxConfig};
use criterion::{black_box, criterion_group, criterion_main, Criterion};
use uuid::Uuid;

fn benchmark_agent_id_generation(c: &mut Criterion) {
    c.bench_function("agent_id_generation", |b| {
        b.iter(|| black_box(AgentId::new()));
    });
}

fn benchmark_agent_config_creation(c: &mut Criterion) {
    c.bench_function("agent_config_creation", |b| {
        b.iter(|| {
            let config = AgentConfig {
                name: "bench-agent".to_string(),
                agent_type: AgentType::User,
                sandbox: SandboxConfig::default(),
                resource_limits: ResourceLimits::default(),
                permissions: vec![],
                metadata: serde_json::Value::Null,
            };
            black_box(config);
        });
    });
}

fn benchmark_orchestrator_task_creation(c: &mut Criterion) {
    c.bench_function("orchestrator_task_creation", |b| {
        b.iter(|| {
            let task = Task {
                id: Uuid::new_v4().to_string(),
                priority: TaskPriority::Normal,
                target_agents: vec![],
                payload: serde_json::json!({"action": "test"}),
                created_at: chrono::Utc::now(),
                deadline: None,
                dependencies: vec![],
            };
            black_box(task);
        });
    });
}

fn benchmark_agent_handle_clone(c: &mut Criterion) {
    let handle = AgentHandle {
        id: AgentId::new(),
        name: "agent-1".to_string(),
        status: AgentStatus::Running,
        created_at: chrono::Utc::now(),
        started_at: None,
        resource_usage: agnos_common::ResourceUsage::default(),
        pid: None,
    };

    c.bench_function("agent_handle_clone", |b| {
        b.iter(|| black_box(handle.clone()));
    });
}

fn benchmark_task_priority_ordering(c: &mut Criterion) {
    c.bench_function("task_priority_ordering", |b| {
        b.iter(|| {
            let priorities = vec![
                TaskPriority::Critical,
                TaskPriority::High,
                TaskPriority::Normal,
                TaskPriority::Low,
                TaskPriority::Background,
            ];
            black_box(priorities);
        });
    });
}

fn benchmark_task_result_serialization(c: &mut Criterion) {
    let result = TaskResult {
        task_id: "task-1".to_string(),
        agent_id: AgentId::new(),
        success: true,
        result: Some(serde_json::json!({"status": "done"})),
        error: None,
        completed_at: chrono::Utc::now(),
        duration_ms: 100,
    };

    c.bench_function("task_result_serialize", |b| {
        b.iter(|| serde_json::to_string(black_box(&result)));
    });
}

fn benchmark_task_payload_json(c: &mut Criterion) {
    c.bench_function("task_payload_json_parse", |b| {
        let payload = r#"{"action": "test", "data": {"key": "value", "items": [1, 2,3]}}"#;
        b.iter(|| serde_json::from_str::<serde_json::Value>(black_box(payload)));
    });
}

fn benchmark_agent_status_enum(c: &mut Criterion) {
    c.bench_function("agent_status_clone", |b| {
        let status = AgentStatus::Running;
        b.iter(|| black_box(status.clone()));
    });
}

fn benchmark_resource_usage_default(c: &mut Criterion) {
    c.bench_function("resource_usage_default", |b| {
        b.iter(|| black_box(agnos_common::ResourceUsage::default()));
    });
}

fn benchmark_agent_handle_creation(c: &mut Criterion) {
    c.bench_function("agent_handle_creation", |b| {
        b.iter(|| {
            let handle = AgentHandle {
                id: AgentId::new(),
                name: "bench-agent".to_string(),
                status: AgentStatus::Running,
                created_at: chrono::Utc::now(),
                started_at: None,
                resource_usage: agnos_common::ResourceUsage::default(),
            };
            black_box(handle);
        });
    });
}

fn benchmark_task_result_creation(c: &mut Criterion) {
    c.bench_function("task_result_creation", |b| {
        b.iter(|| {
            let result = TaskResult {
                task_id: Uuid::new_v4().to_string(),
                agent_id: AgentId::new(),
                success: true,
                result: Some(serde_json::json!({"status": "done"})),
                error: None,
                completed_at: chrono::Utc::now(),
                duration_ms: 100,
            };
            black_box(result);
        });
    });
}

criterion_group!(
    benches,
    benchmark_agent_id_generation,
    benchmark_agent_config_creation,
    benchmark_orchestrator_task_creation,
    benchmark_agent_handle_clone,
    benchmark_task_priority_ordering,
    benchmark_task_result_serialization,
    benchmark_task_payload_json,
    benchmark_agent_status_enum,
    benchmark_resource_usage_default,
    benchmark_agent_handle_creation,
    benchmark_task_result_creation
);
criterion_main!(benches);

//! Agent representation and lifecycle management

use std::path::PathBuf;
use std::process::Stdio;
use std::time::{Duration, Instant};

use anyhow::{Context, Result};
use tokio::process::{Child, Command};
use tokio::sync::{mpsc, RwLock};
use tracing::{debug, error, info, warn};
use uuid::Uuid;

use agnos_common::{
    AgentConfig, AgentId, AgentStatus, AgentType, Message, ResourceUsage, StopReason,
};

use crate::ipc::AgentIpc;
use crate::sandbox::Sandbox;

/// Handle to a running agent
#[derive(Debug, Clone)]
pub struct AgentHandle {
    pub id: AgentId,
    pub name: String,
    pub status: AgentStatus,
    pub created_at: chrono::DateTime<chrono::Utc>,
    pub started_at: Option<chrono::DateTime<chrono::Utc>>,
    pub resource_usage: ResourceUsage,
    /// PID of the agent process (if spawned)
    pub pid: Option<u32>,
}

/// Represents a running agent process
pub struct Agent {
    id: AgentId,
    config: AgentConfig,
    status: RwLock<AgentStatus>,
    process: Option<Child>,
    ipc: Option<AgentIpc>,
    sandbox: Sandbox,
    started_at: Option<Instant>,
    message_tx: mpsc::Sender<Message>,
    message_rx: Option<mpsc::Receiver<Message>>,
}

impl Agent {
    /// Create a new agent from configuration
    pub async fn new(config: AgentConfig) -> Result<(Self, mpsc::Receiver<Message>)> {
        let id = AgentId::new();
        let (message_tx, message_rx) = mpsc::channel(100);

        let sandbox = Sandbox::new(&config.sandbox)
            .with_context(|| "Failed to create agent sandbox")?;

        let agent = Self {
            id,
            config,
            status: RwLock::new(AgentStatus::Pending),
            process: None,
            ipc: None,
            sandbox,
            started_at: None,
            message_tx,
            message_rx: None,
        };

        Ok((agent, message_rx))
    }

    /// Get agent ID
    pub fn id(&self) -> AgentId {
        self.id
    }

    /// Get agent handle for external reference
    pub async fn handle(&self) -> AgentHandle {
        let pid = self.process.as_ref().and_then(|p| p.id());
        AgentHandle {
            id: self.id,
            name: self.config.name.clone(),
            status: *self.status.read().await,
            created_at: chrono::Utc::now(),
            started_at: None,
            resource_usage: ResourceUsage::default(),
            pid,
        }
    }

    /// Start the agent process
    pub async fn start(&mut self) -> Result<()> {
        let mut status = self.status.write().await;

        if *status != AgentStatus::Pending && *status != AgentStatus::Stopped {
            return Err(anyhow::anyhow!("Agent is not in a startable state: {:?}", *status));
        }

        *status = AgentStatus::Starting;
        drop(status);

        info!("Starting agent {} ({})", self.config.name, self.id);

        // Apply sandbox restrictions
        self.sandbox.apply().await?;

        // Spawn agent process
        let executable = self.find_agent_executable().await?;

        let mut cmd = Command::new(&executable);
        cmd.arg("--agent-id")
            .arg(self.id.to_string())
            .arg("--agent-name")
            .arg(&self.config.name)
            .stdin(Stdio::null())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped());

        // Apply resource limits
        if let Some(rlimits) = self.build_resource_limits() {
            unsafe {
                cmd.pre_exec(move || {
                    rlimits.apply()?;
                    Ok(())
                });
            }
        }

        let mut child = cmd.spawn()
            .with_context(|| format!("Failed to spawn agent process: {}", executable.display()))?;

        info!("Agent {} started with PID {:?}", self.id, child.id());

        self.process = Some(child);
        self.started_at = Some(Instant::now());

        let mut status = self.status.write().await;
        *status = AgentStatus::Running;

        Ok(())
    }

    /// Stop the agent gracefully
    pub async fn stop(&mut self, reason: StopReason) -> Result<()> {
        info!("Stopping agent {}: {:?}", self.id, reason);

        let mut status = self.status.write().await;
        *status = AgentStatus::Stopping;
        drop(status);

        // Send graceful shutdown signal
        if let Some(ref mut process) = self.process {
            #[cfg(unix)]
            {
                use nix::sys::signal::{self, Signal};
                use nix::unistd::Pid;

                if let Some(pid) = process.id() {
                    let _ = signal::kill(Pid::from_raw(pid as i32), Signal::SIGTERM);
                }
            }

            // Wait for graceful shutdown with timeout
            match tokio::time::timeout(Duration::from_secs(10), process.wait()).await {
                Ok(Ok(_)) => {
                    info!("Agent {} stopped gracefully", self.id);
                }
                Ok(Err(e)) => {
                    warn!("Agent {} exit error: {}", self.id, e);
                    process.kill().await.ok();
                }
                Err(_) => {
                    warn!("Agent {} shutdown timeout, forcing kill", self.id);
                    process.kill().await.ok();
                }
            }
        }

        let mut status = self.status.write().await;
        *status = AgentStatus::Stopped;

        Ok(())
    }

    /// Pause the agent (suspend execution via SIGSTOP)
    pub async fn pause(&mut self) -> Result<()> {
        let mut status = self.status.write().await;
        if *status != AgentStatus::Running {
            return Err(anyhow::anyhow!("Cannot pause agent in state: {:?}", *status));
        }

        // Send SIGSTOP to actually suspend the process
        if let Some(ref process) = self.process {
            if let Some(pid) = process.id() {
                #[cfg(unix)]
                {
                    use nix::sys::signal::{self, Signal};
                    use nix::unistd::Pid;
                    signal::kill(Pid::from_raw(pid as i32), Signal::SIGSTOP)
                        .map_err(|e| anyhow::anyhow!("Failed to SIGSTOP agent {}: {}", self.id, e))?;
                }
            }
        }

        *status = AgentStatus::Paused;
        info!("Agent {} paused (SIGSTOP)", self.id);
        Ok(())
    }

    /// Resume a paused agent (via SIGCONT)
    pub async fn resume(&mut self) -> Result<()> {
        let mut status = self.status.write().await;
        if *status != AgentStatus::Paused {
            return Err(anyhow::anyhow!("Cannot resume agent in state: {:?}", *status));
        }

        // Send SIGCONT to resume the process
        if let Some(ref process) = self.process {
            if let Some(pid) = process.id() {
                #[cfg(unix)]
                {
                    use nix::sys::signal::{self, Signal};
                    use nix::unistd::Pid;
                    signal::kill(Pid::from_raw(pid as i32), Signal::SIGCONT)
                        .map_err(|e| anyhow::anyhow!("Failed to SIGCONT agent {}: {}", self.id, e))?;
                }
            }
        }

        *status = AgentStatus::Running;
        info!("Agent {} resumed (SIGCONT)", self.id);
        Ok(())
    }

    /// Get current resource usage by reading from `/proc/{pid}/`.
    ///
    /// Returns real memory (VmRSS), CPU time (utime+stime), FD count, and
    /// thread count for the agent's process.  Falls back to defaults if the
    /// process has no PID or `/proc` is unavailable.
    pub async fn resource_usage(&self) -> ResourceUsage {
        let pid = match self.process.as_ref().and_then(|p| p.id()) {
            Some(p) => p,
            None => return ResourceUsage::default(),
        };

        let memory_used = Self::read_vm_rss(pid);
        let cpu_time_used = Self::read_cpu_time_ms(pid);
        let file_descriptors_used = Self::count_fds(pid);
        let processes_used = Self::count_threads(pid);

        ResourceUsage {
            memory_used,
            cpu_time_used,
            file_descriptors_used,
            processes_used,
        }
    }

    /// Read VmRSS from /proc/{pid}/status in bytes.
    fn read_vm_rss(pid: u32) -> u64 {
        let path = format!("/proc/{}/status", pid);
        std::fs::read_to_string(&path)
            .ok()
            .and_then(|contents| {
                for line in contents.lines() {
                    if let Some(val) = line.strip_prefix("VmRSS:") {
                        let kb: u64 = val.trim().split_whitespace().next()?.parse().ok()?;
                        return Some(kb * 1024);
                    }
                }
                None
            })
            .unwrap_or(0)
    }

    /// Read CPU time (utime + stime) from /proc/{pid}/stat in milliseconds.
    fn read_cpu_time_ms(pid: u32) -> u64 {
        let path = format!("/proc/{}/stat", pid);
        std::fs::read_to_string(&path)
            .ok()
            .and_then(|contents| {
                let after_comm = contents.find(')')?.checked_add(2)?;
                let fields: Vec<&str> = contents[after_comm..].split_whitespace().collect();
                let utime: u64 = fields.get(11)?.parse().ok()?;
                let stime: u64 = fields.get(12)?.parse().ok()?;
                let ticks = utime + stime;
                let ticks_per_sec = unsafe { libc::sysconf(libc::_SC_CLK_TCK) } as u64;
                if ticks_per_sec > 0 {
                    Some(ticks * 1000 / ticks_per_sec)
                } else {
                    Some(ticks * 10) // fallback: assume 100 Hz
                }
            })
            .unwrap_or(0)
    }

    /// Count open file descriptors from /proc/{pid}/fd/.
    fn count_fds(pid: u32) -> u32 {
        let path = format!("/proc/{}/fd", pid);
        std::fs::read_dir(&path)
            .map(|entries| entries.count() as u32)
            .unwrap_or(0)
    }

    /// Count threads from /proc/{pid}/task/.
    fn count_threads(pid: u32) -> u32 {
        let path = format!("/proc/{}/task", pid);
        std::fs::read_dir(&path)
            .map(|entries| entries.count() as u32)
            .unwrap_or(1) // at least 1 thread (the main thread)
    }

    /// Send a message to the agent
    pub async fn send_message(&self, message: Message) -> Result<()> {
        self.message_tx.send(message).await
            .map_err(|_| anyhow::anyhow!("Failed to send message to agent"))?;
        Ok(())
    }

    /// Check if the agent is still running
    pub async fn is_running(&self) -> bool {
        let status = self.status.read().await;
        *status == AgentStatus::Running
    }

    /// Find the executable for this agent type
    async fn find_agent_executable(&self) -> Result<PathBuf> {
        // Look for agent implementations in standard locations
        let search_paths = vec![
            PathBuf::from("/usr/lib/agnos/agents"),
            PathBuf::from("/opt/agnos/agents"),
            PathBuf::from("./agents"),
        ];

        let agent_type = format!("{:?}", self.config.agent_type).to_lowercase();
        let executable_name = format!("agnos-agent-{}-agent", agent_type);

        for path in search_paths {
            let executable = path.join(&executable_name);
            if executable.exists() {
                return Ok(executable);
            }
        }

        // Default to a generic agent runner
        Ok(PathBuf::from("/usr/bin/agnos-agent-runner"))
    }

    fn build_resource_limits(&self) -> Option<ResourceLimits> {
        Some(ResourceLimits {
            max_memory: self.config.resource_limits.max_memory,
            max_cpu_time: self.config.resource_limits.max_cpu_time,
        })
    }
}

/// Resource limits for agent processes
struct ResourceLimits {
    max_memory: u64,
    max_cpu_time: u64,
}

impl ResourceLimits {
    fn apply(&self) -> std::io::Result<()> {
        #[cfg(unix)]
        {
            use libc::{rlimit, setrlimit, RLIMIT_AS, RLIMIT_CPU};

            // Set memory limit
            if self.max_memory > 0 {
                let limit = rlimit {
                    rlim_cur: self.max_memory,
                    rlim_max: self.max_memory,
                };
                unsafe {
                    setrlimit(RLIMIT_AS, &limit);
                }
            }

            // Set CPU time limit
            if self.max_cpu_time > 0 {
                let limit = rlimit {
                    rlim_cur: self.max_cpu_time,
                    rlim_max: self.max_cpu_time,
                };
                unsafe {
                    setrlimit(RLIMIT_CPU, &limit);
                }
            }
        }

        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_agent_handle_default() {
        let handle = AgentHandle {
            id: AgentId::new(),
            name: "test-agent".to_string(),
            status: AgentStatus::Pending,
            created_at: chrono::Utc::now(),
            started_at: None,
            resource_usage: ResourceUsage::default(),
            pid: None,
        };

        assert_eq!(handle.name, "test-agent");
        assert_eq!(handle.status, AgentStatus::Pending);
        assert!(handle.pid.is_none());
    }

    #[test]
    fn test_agent_handle_running() {
        let handle = AgentHandle {
            id: AgentId::new(),
            name: "running-agent".to_string(),
            status: AgentStatus::Running,
            created_at: chrono::Utc::now(),
            started_at: Some(chrono::Utc::now()),
            resource_usage: ResourceUsage {
                memory_used: 1024 * 1024 * 100,
                cpu_time_used: 50000,
                file_descriptors_used: 5,
                processes_used: 1,
            },
            pid: Some(12345),
        };

        assert_eq!(handle.status, AgentStatus::Running);
        assert!(handle.pid.is_some());
        assert_eq!(handle.pid, Some(12345));
        assert!(handle.resource_usage.memory_used > 0);
    }

    #[test]
    fn test_agent_handle_debug() {
        let handle = AgentHandle {
            id: AgentId::new(),
            name: "debug-agent".to_string(),
            status: AgentStatus::Stopped,
            created_at: chrono::Utc::now(),
            started_at: None,
            resource_usage: ResourceUsage::default(),
            pid: None,
        };

        let debug_str = format!("{:?}", handle);
        assert!(debug_str.contains("debug-agent"));
        assert!(debug_str.contains("Stopped"));
    }

    #[test]
    fn test_resource_limits_default() {
        let limits = ResourceLimits {
            max_memory: 0,
            max_cpu_time: 0,
        };

        assert_eq!(limits.max_memory, 0);
        assert_eq!(limits.max_cpu_time, 0);
    }

    #[test]
    fn test_resource_limits_custom() {
        let limits = ResourceLimits {
            max_memory: 1024 * 1024 * 1024,
            max_cpu_time: 3600,
        };

        assert_eq!(limits.max_memory, 1024 * 1024 * 1024);
        assert_eq!(limits.max_cpu_time, 3600);
    }

    #[test]
    fn test_resource_limits_apply_zero() {
        let limits = ResourceLimits {
            max_memory: 0,
            max_cpu_time: 0,
        };

        let result = limits.apply();
        assert!(result.is_ok());
    }

    #[test]
    fn test_agent_id_new_unique() {
        let id1 = AgentId::new();
        let id2 = AgentId::new();

        assert_ne!(id1, id2);
    }

    #[test]
    fn test_agent_status_variants() {
        assert_eq!(format!("{:?}", AgentStatus::Pending), "Pending");
        assert_eq!(format!("{:?}", AgentStatus::Starting), "Starting");
        assert_eq!(format!("{:?}", AgentStatus::Running), "Running");
        assert_eq!(format!("{:?}", AgentStatus::Stopping), "Stopping");
        assert_eq!(format!("{:?}", AgentStatus::Stopped), "Stopped");
        assert_eq!(format!("{:?}", AgentStatus::Failed), "Failed");
    }

    #[test]
    fn test_agent_status_is_stopped() {
        assert_eq!(AgentStatus::Pending, AgentStatus::Pending);
        assert_eq!(AgentStatus::Stopped, AgentStatus::Stopped);
        assert_eq!(AgentStatus::Failed, AgentStatus::Failed);
    }
}

//! Agent Registration HTTP API
//!
//! Axum HTTP server on port 8090 providing REST endpoints for external
//! consumers (AGNOSTIC, SecureYeoman) to register agents, send heartbeats,
//! and query agent status.

use std::collections::HashMap;
use std::net::SocketAddr;
use std::sync::Arc;

use axum::extract::{Path, State};
use axum::http::StatusCode;
use axum::response::IntoResponse;
use axum::routing::{delete, get, post};
use axum::{Json, Router};
use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use tokio::sync::RwLock;
use tracing::{debug, error, info, warn};
use uuid::Uuid;

/// Default listen port for the agent registration API.
pub const DEFAULT_PORT: u16 = 8090;

// ---------------------------------------------------------------------------
// Request / Response types
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RegisterAgentRequest {
    pub name: String,
    #[serde(default)]
    pub capabilities: Vec<String>,
    #[serde(default)]
    pub resource_needs: ResourceNeeds,
    #[serde(default)]
    pub metadata: HashMap<String, String>,
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct ResourceNeeds {
    #[serde(default)]
    pub min_memory_mb: u64,
    #[serde(default)]
    pub min_cpu_shares: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RegisterAgentResponse {
    pub id: Uuid,
    pub name: String,
    pub status: String,
    pub registered_at: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HeartbeatRequest {
    #[serde(default)]
    pub status: Option<String>,
    #[serde(default)]
    pub current_task: Option<String>,
    #[serde(default)]
    pub cpu_percent: Option<f32>,
    #[serde(default)]
    pub memory_mb: Option<u64>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AgentDetail {
    pub id: Uuid,
    pub name: String,
    pub status: String,
    pub capabilities: Vec<String>,
    pub resource_needs: ResourceNeeds,
    pub metadata: HashMap<String, String>,
    pub registered_at: DateTime<Utc>,
    pub last_heartbeat: Option<DateTime<Utc>>,
    pub current_task: Option<String>,
    pub cpu_percent: Option<f32>,
    pub memory_mb: Option<u64>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AgentListResponse {
    pub agents: Vec<AgentDetail>,
    pub total: usize,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HealthResponse {
    pub status: String,
    pub service: String,
    pub version: String,
    pub agents_registered: usize,
    pub uptime_seconds: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ErrorResponse {
    pub error: String,
    pub code: u16,
}

// ---------------------------------------------------------------------------
// Shared state
// ---------------------------------------------------------------------------

#[derive(Debug, Clone)]
pub struct RegisteredAgentEntry {
    pub detail: AgentDetail,
}

#[derive(Debug, Clone)]
pub struct ApiState {
    agents: Arc<RwLock<HashMap<Uuid, RegisteredAgentEntry>>>,
    started_at: DateTime<Utc>,
}

impl ApiState {
    pub fn new() -> Self {
        Self {
            agents: Arc::new(RwLock::new(HashMap::new())),
            started_at: Utc::now(),
        }
    }
}

impl Default for ApiState {
    fn default() -> Self {
        Self::new()
    }
}

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------

async fn health_handler(State(state): State<ApiState>) -> impl IntoResponse {
    let agents = state.agents.read().await;
    let uptime = (Utc::now() - state.started_at).num_seconds().max(0) as u64;

    Json(HealthResponse {
        status: "ok".to_string(),
        service: "agnos-agent-runtime".to_string(),
        version: env!("CARGO_PKG_VERSION").to_string(),
        agents_registered: agents.len(),
        uptime_seconds: uptime,
    })
}

async fn register_agent_handler(
    State(state): State<ApiState>,
    Json(req): Json<RegisterAgentRequest>,
) -> impl IntoResponse {
    if req.name.is_empty() {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"error": "Agent name is required", "code": 400})),
        )
            .into_response();
    }

    if req.name.len() > 256 {
        return (
            StatusCode::BAD_REQUEST,
            Json(serde_json::json!({"error": "Agent name too long (max 256)", "code": 400})),
        )
            .into_response();
    }

    let mut agents = state.agents.write().await;

    // Check for duplicate names
    if agents.values().any(|a| a.detail.name == req.name) {
        return (
            StatusCode::CONFLICT,
            Json(serde_json::json!({"error": format!("Agent '{}' already registered", req.name), "code": 409})),
        )
            .into_response();
    }

    let id = Uuid::new_v4();
    let now = Utc::now();

    let detail = AgentDetail {
        id,
        name: req.name.clone(),
        status: "registered".to_string(),
        capabilities: req.capabilities,
        resource_needs: req.resource_needs,
        metadata: req.metadata,
        registered_at: now,
        last_heartbeat: None,
        current_task: None,
        cpu_percent: None,
        memory_mb: None,
    };

    agents.insert(id, RegisteredAgentEntry {
        detail: detail.clone(),
    });

    info!("Agent registered: {} ({})", req.name, id);

    let resp = RegisterAgentResponse {
        id,
        name: req.name,
        status: "registered".to_string(),
        registered_at: now,
    };

    (StatusCode::CREATED, Json(serde_json::to_value(resp).unwrap())).into_response()
}

async fn heartbeat_handler(
    State(state): State<ApiState>,
    Path(id): Path<Uuid>,
    Json(req): Json<HeartbeatRequest>,
) -> impl IntoResponse {
    let mut agents = state.agents.write().await;

    match agents.get_mut(&id) {
        Some(entry) => {
            entry.detail.last_heartbeat = Some(Utc::now());
            if let Some(status) = req.status {
                entry.detail.status = status;
            }
            if let Some(task) = req.current_task {
                entry.detail.current_task = Some(task);
            }
            if let Some(cpu) = req.cpu_percent {
                entry.detail.cpu_percent = Some(cpu);
            }
            if let Some(mem) = req.memory_mb {
                entry.detail.memory_mb = Some(mem);
            }

            debug!("Heartbeat received from agent {}", id);
            (StatusCode::OK, Json(serde_json::json!({"status": "ok"}))).into_response()
        }
        None => (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({"error": format!("Agent {} not found", id), "code": 404})),
        )
            .into_response(),
    }
}

async fn list_agents_handler(State(state): State<ApiState>) -> impl IntoResponse {
    let agents = state.agents.read().await;
    let agent_list: Vec<AgentDetail> = agents.values().map(|a| a.detail.clone()).collect();
    let total = agent_list.len();

    Json(AgentListResponse {
        agents: agent_list,
        total,
    })
}

async fn get_agent_handler(
    State(state): State<ApiState>,
    Path(id): Path<Uuid>,
) -> impl IntoResponse {
    let agents = state.agents.read().await;

    match agents.get(&id) {
        Some(entry) => (StatusCode::OK, Json(serde_json::to_value(&entry.detail).unwrap())).into_response(),
        None => (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({"error": format!("Agent {} not found", id), "code": 404})),
        )
            .into_response(),
    }
}

async fn deregister_agent_handler(
    State(state): State<ApiState>,
    Path(id): Path<Uuid>,
) -> impl IntoResponse {
    let mut agents = state.agents.write().await;

    match agents.remove(&id) {
        Some(entry) => {
            info!("Agent deregistered: {} ({})", entry.detail.name, id);
            (StatusCode::OK, Json(serde_json::json!({"status": "deregistered", "id": id.to_string()}))).into_response()
        }
        None => (
            StatusCode::NOT_FOUND,
            Json(serde_json::json!({"error": format!("Agent {} not found", id), "code": 404})),
        )
            .into_response(),
    }
}

// ---------------------------------------------------------------------------
// Router & server
// ---------------------------------------------------------------------------

/// Build the Axum router for the agent registration API.
pub fn build_router(state: ApiState) -> Router {
    Router::new()
        .route("/v1/health", get(health_handler))
        .route("/v1/agents/register", post(register_agent_handler))
        .route("/v1/agents/:id/heartbeat", post(heartbeat_handler))
        .route("/v1/agents", get(list_agents_handler))
        .route("/v1/agents/:id", get(get_agent_handler))
        .route("/v1/agents/:id", delete(deregister_agent_handler))
        .with_state(state)
}

/// Start the HTTP API server on the given port.
pub async fn start_server(port: u16) -> anyhow::Result<()> {
    let state = ApiState::new();
    let app = build_router(state);

    let addr = SocketAddr::from(([0, 0, 0, 0], port));
    info!("Agent Registration API listening on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await?;
    axum::serve(listener, app).await?;

    Ok(())
}

