//! Agent SDK for building AGNOS agents
//!
//! Provides a high-level API for agent development with automatic
//! registration, resource management, and communication.

use std::sync::Arc;

use anyhow::{Context, Result};
use tokio::sync::{mpsc, RwLock};
use tracing::{debug, info, warn};

use agnos_common::{
    AgentConfig, AgentId, AgentStatus, Message, MessageType, ResourceUsage,
};

/// Agent context passed to all agent implementations
pub struct AgentContext {
    pub id: AgentId,
    pub config: AgentConfig,
    pub status: RwLock<AgentStatus>,
    message_tx: mpsc::Sender<Message>,
}

impl AgentContext {
    /// Create a new agent context
    pub fn new(config: AgentConfig) -> (Self, mpsc::Receiver<Message>) {
        let id = AgentId::new();
        let (message_tx, message_rx) = mpsc::channel(100);

        let ctx = Self {
            id,
            config,
            status: RwLock::new(AgentStatus::Starting),
            message_tx,
        };

        (ctx, message_rx)
    }

    /// Send a message to another agent
    pub async fn send_message(&self, target: &str, payload: agnos_common::serde_json::Value) -> Result<()> {
        let message = Message {
            id: uuid::Uuid::new_v4().to_string(),
            source: self.config.name.clone(),
            target: target.to_string(),
            message_type: MessageType::Command,
            payload,
            timestamp: chrono::Utc::now(),
        };

        self.message_tx.send(message).await
            .map_err(|_| anyhow::anyhow!("Failed to send message"))?;

        Ok(())
    }

    /// Get current agent status
    pub async fn status(&self) -> AgentStatus {
        *self.status.read().await
    }

    /// Update agent status
    pub async fn set_status(&self, status: AgentStatus) {
        let mut s = self.status.write().await;
        *s = status;
        debug!("Agent {} status changed to {:?}", self.id, status);
    }
}

/// Trait that all AGNOS agents must implement
#[async_trait::async_trait]
pub trait Agent: Send + Sync {
    /// Initialize the agent
    async fn init(&mut self, ctx: &AgentContext) -> Result<()>;

    /// Main agent loop
    async fn run(&mut self, ctx: &AgentContext) -> Result<()>;

    /// Handle incoming messages
    async fn handle_message(&mut self, ctx: &AgentContext, message: Message) -> Result<()>;

    /// Cleanup before shutdown
    async fn shutdown(&mut self, ctx: &AgentContext) -> Result<()>;
}

/// Agent runtime for executing agents
pub struct AgentRuntime {
    ctx: Arc<AgentContext>,
    message_rx: Option<mpsc::Receiver<Message>>,
}

impl AgentRuntime {
    /// Create a new agent runtime
    pub fn new(config: AgentConfig) -> Self {
        let (ctx, message_rx) = AgentContext::new(config);
        let ctx = Arc::new(ctx);

        Self {
            ctx,
            message_rx: Some(message_rx),
        }
    }

    /// Run an agent implementation
    pub async fn run<A: Agent>(mut self, mut agent: A) -> Result<()> {
        info!("Starting agent runtime for {}", self.ctx.config.name);

        // Initialize the agent
        agent.init(&self.ctx).await
            .with_context(|| "Agent initialization failed")?;

        self.ctx.set_status(AgentStatus::Running).await;

        info!("Agent {} is running", self.ctx.config.name);

        // Get the message receiver if available
        let message_rx = self.message_rx.take();

        // Run the main agent loop with message handling
        let agent_result = self.run_message_loop(&mut agent, message_rx).await;

        // Cleanup
        self.ctx.set_status(AgentStatus::Stopping).await;
        agent.shutdown(&self.ctx).await?;
        self.ctx.set_status(AgentStatus::Stopped).await;

        info!("Agent {} stopped", self.ctx.config.name);

        agent_result
    }

    async fn run_message_loop<A: Agent>(
        &self,
        agent: &mut A,
        mut message_rx: Option<mpsc::Receiver<Message>>,
    ) -> Result<()> {
        let agent_name = self.ctx.config.name.clone();

        loop {
            tokio::select! {
                // Handle incoming messages
                Some(message) = async {
                    if let Some(rx) = message_rx.as_mut() {
                        rx.recv().await
                    } else {
                        None
                    }
                } => {
                    debug!("Agent {} received message: {}", agent_name, message.id);

                    if let Err(e) = agent.handle_message(&self.ctx, message).await {
                        warn!("Error handling message: {}", e);
                    }
                }
                // Run the agent's main loop
                result = agent.run(&self.ctx) => {
                    result?;
                    // Agent run() returned, which means the agent wants to stop
                    break;
                }
            }
        }

        Ok(())
    }
}

/// Helper functions for agents
pub mod helpers {
    use super::*;
    use std::time::Duration;

    use sha2::{Digest, Sha256};

    pub const LLM_GATEWAY_ADDR: &str = "http://localhost:8088";
    const LLM_GATEWAY_TIMEOUT: Duration = Duration::from_secs(60);
    const AUDIT_LOG_PATH: &str = "/var/log/agnos/audit.log";
    const AUDIT_LOG_DIR: &str = "/var/log/agnos";

    /// Shared HTTP client — reuses connection pool across all helper calls.
    fn shared_client() -> &'static reqwest::Client {
        static CLIENT: once_cell::sync::Lazy<reqwest::Client> =
            once_cell::sync::Lazy::new(|| {
                reqwest::Client::builder()
                    .timeout(LLM_GATEWAY_TIMEOUT)
                    .pool_max_idle_per_host(4)
                    .build()
                    .unwrap_or_else(|e| {
                        tracing::error!("Failed to build reqwest client: {}, using default", e);
                        reqwest::Client::new()
                    })
            });
        &CLIENT
    }

    /// Request LLM inference through the gateway
    pub async fn llm_inference(prompt: &str, model: Option<&str>) -> Result<String> {
        let client = shared_client();

        let request_body = serde_json::json!({
            "model": model.unwrap_or("default"),
            "messages": [
                {"role": "user", "content": prompt}
            ],
            "max_tokens": 1024,
            "temperature": 0.7
        });

        let response = client
            .post(format!("{}/v1/chat/completions", LLM_GATEWAY_ADDR))
            .json(&request_body)
            .send()
            .await
            .map_err(|e| anyhow::anyhow!("LLM gateway request failed: {}", e))?;

        if !response.status().is_success() {
            return Err(anyhow::anyhow!("LLM gateway error: {}", response.status()));
        }

        let response_body: serde_json::Value = response.json().await
            .map_err(|e| anyhow::anyhow!("Failed to parse LLM response: {}", e))?;

        let content = response_body["choices"]
            .as_array()
            .and_then(|arr| arr.first())
            .and_then(|c| c["message"]["content"].as_str())
            .unwrap_or("")
            .to_string();

        debug!("LLM inference completed: {} chars", content.len());
        Ok(content)
    }

    /// Request LLM inference with full options
    pub async fn llm_inference_with_options(
        prompt: &str,
        model: Option<&str>,
        temperature: Option<f32>,
        max_tokens: Option<u32>,
    ) -> Result<String> {
        let client = shared_client();

        let mut request_body = serde_json::json!({
            "model": model.unwrap_or("default"),
            "messages": [
                {"role": "user", "content": prompt}
            ]
        });

        if let Some(temp) = temperature {
            request_body["temperature"] = serde_json::json!(temp);
        }
        if let Some(tokens) = max_tokens {
            request_body["max_tokens"] = serde_json::json!(tokens);
        }

        let response = client
            .post(format!("{}/v1/chat/completions", LLM_GATEWAY_ADDR))
            .json(&request_body)
            .send()
            .await
            .map_err(|e| anyhow::anyhow!("LLM gateway request failed: {}", e))?;

        if !response.status().is_success() {
            return Err(anyhow::anyhow!("LLM gateway error: {}", response.status()));
        }

        let response_body: serde_json::Value = response.json().await
            .map_err(|e| anyhow::anyhow!("Failed to parse LLM response: {}", e))?;

        let content = response_body["choices"]
            .as_array()
            .and_then(|arr| arr.first())
            .and_then(|c| c["message"]["content"].as_str())
            .unwrap_or("")
            .to_string();

        debug!("LLM inference completed: {} chars", content.len());
        Ok(content)
    }

    /// Check if LLM gateway is available
    pub async fn llm_gateway_health() -> Result<bool> {
        let client = shared_client();

        match client
            .get(format!("{}/v1/health", LLM_GATEWAY_ADDR))
            .timeout(Duration::from_secs(5))
            .send()
            .await
        {
            Ok(response) => Ok(response.status().is_success()),
            Err(_) => Ok(false),
        }
    }

    /// List available models from gateway
    pub async fn llm_list_models() -> Result<Vec<String>> {
        let client = shared_client();

        let response = client
            .get(format!("{}/v1/models", LLM_GATEWAY_ADDR))
            .send()
            .await
            .map_err(|e| anyhow::anyhow!("LLM gateway request failed: {}", e))?;

        if !response.status().is_success() {
            return Err(anyhow::anyhow!("LLM gateway error: {}", response.status()));
        }

        let response_body: serde_json::Value = response.json().await
            .map_err(|e| anyhow::anyhow!("Failed to parse LLM response: {}", e))?;

        let models: Vec<String> = response_body["data"]
            .as_array()
            .map(|arr| {
                arr.iter()
                    .filter_map(|m| m["id"].as_str().map(String::from))
                    .collect()
            })
            .unwrap_or_default();

        Ok(models)
    }

    /// Log an audit event to `/var/log/agnos/audit.log` with cryptographic hash chain.
    ///
    /// Each entry is a JSON line containing the event data plus a SHA-256 hash
    /// that chains to the previous entry, providing tamper evidence.  The file
    /// is created (with directory) if it doesn't exist.  Writes are appended
    /// atomically with a file lock.
    pub async fn audit_log(event_type: &str, details: agnos_common::serde_json::Value) -> Result<()> {
        debug!("Audit log: {} - {:?}", event_type, details);

        // Build the log entry
        let timestamp = chrono::Utc::now().to_rfc3339();
        let previous_hash = read_last_hash().unwrap_or_else(|| "genesis".to_string());

        // Hash = SHA-256(previous_hash || timestamp || event_type || details)
        let mut hasher = Sha256::new();
        hasher.update(previous_hash.as_bytes());
        hasher.update(timestamp.as_bytes());
        hasher.update(event_type.as_bytes());
        hasher.update(details.to_string().as_bytes());
        let hash = format!("{:x}", hasher.finalize());

        let entry = serde_json::json!({
            "timestamp": timestamp,
            "event_type": event_type,
            "details": details,
            "previous_hash": previous_hash,
            "hash": hash,
        });

        // Ensure the directory exists
        if let Err(e) = std::fs::create_dir_all(AUDIT_LOG_DIR) {
            warn!("Could not create audit log directory {}: {}", AUDIT_LOG_DIR, e);
            // Still log to debug as fallback
            return Ok(());
        }

        // Append atomically with exclusive file lock
        use std::io::Write;
        match std::fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(AUDIT_LOG_PATH)
        {
            Ok(mut file) => {
                // Use advisory lock for concurrent writers
                #[cfg(unix)]
                {
                    use std::os::unix::io::AsRawFd;
                    let fd = file.as_raw_fd();
                    unsafe {
                        libc::flock(fd, libc::LOCK_EX);
                    }
                }

                let line = format!("{}\n", entry);
                if let Err(e) = file.write_all(line.as_bytes()) {
                    warn!("Failed to write audit log: {}", e);
                }

                #[cfg(unix)]
                {
                    use std::os::unix::io::AsRawFd;
                    let fd = file.as_raw_fd();
                    unsafe {
                        libc::flock(fd, libc::LOCK_UN);
                    }
                }
            }
            Err(e) => {
                warn!("Could not open audit log {}: {}", AUDIT_LOG_PATH, e);
            }
        }

        Ok(())
    }

    /// Read the hash from the last line of the audit log (for chaining).
    fn read_last_hash() -> Option<String> {
        let contents = std::fs::read_to_string(AUDIT_LOG_PATH).ok()?;
        let last_line = contents.lines().rev().find(|l| !l.trim().is_empty())?;
        let entry: serde_json::Value = serde_json::from_str(last_line).ok()?;
        entry["hash"].as_str().map(String::from)
    }

    /// Check resource usage for the current process by reading from `/proc/self/`.
    pub async fn check_resources() -> ResourceUsage {
        let pid = std::process::id();

        let memory_used = read_vm_rss(pid);
        let cpu_time_used = read_cpu_time_ms(pid);
        let file_descriptors_used = count_fds(pid);
        let processes_used = count_threads(pid);

        ResourceUsage {
            memory_used,
            cpu_time_used,
            file_descriptors_used,
            processes_used,
        }
    }

    fn read_vm_rss(pid: u32) -> u64 {
        let path = format!("/proc/{}/status", pid);
        std::fs::read_to_string(&path)
            .ok()
            .and_then(|contents| {
                for line in contents.lines() {
                    if let Some(val) = line.strip_prefix("VmRSS:") {
                        let kb: u64 = val.trim().split_whitespace().next()?.parse().ok()?;
                        return Some(kb * 1024);
                    }
                }
                None
            })
            .unwrap_or(0)
    }

    fn read_cpu_time_ms(pid: u32) -> u64 {
        let path = format!("/proc/{}/stat", pid);
        std::fs::read_to_string(&path)
            .ok()
            .and_then(|contents| {
                let after_comm = contents.find(')')?.checked_add(2)?;
                let fields: Vec<&str> = contents[after_comm..].split_whitespace().collect();
                let utime: u64 = fields.get(11)?.parse().ok()?;
                let stime: u64 = fields.get(12)?.parse().ok()?;
                let ticks = utime + stime;
                let ticks_per_sec = unsafe { libc::sysconf(libc::_SC_CLK_TCK) } as u64;
                if ticks_per_sec > 0 {
                    Some(ticks * 1000 / ticks_per_sec)
                } else {
                    Some(ticks * 10)
                }
            })
            .unwrap_or(0)
    }

    fn count_fds(pid: u32) -> u32 {
        let path = format!("/proc/{}/fd", pid);
        std::fs::read_dir(&path)
            .map(|entries| entries.count() as u32)
            .unwrap_or(0)
    }

    fn count_threads(pid: u32) -> u32 {
        let path = format!("/proc/{}/task", pid);
        std::fs::read_dir(&path)
            .map(|entries| entries.count() as u32)
            .unwrap_or(1)
    }
}

/// Macros for agent development
#[macro_export]
macro_rules! agent_main {
    ($agent_type:ty) => {
        #[tokio::main]
        async fn main() -> anyhow::Result<()> {
            use agnos_sys::agent::{AgentRuntime};

            tracing_subscriber::fmt::init();

            // Load configuration from environment or defaults
            let config = agnos_common::AgentConfig {
                name: env!("CARGO_PKG_NAME").to_string(),
                agent_type: agnos_common::AgentType::Service,
                ..Default::default()
            };

            let runtime = AgentRuntime::new(config);
            let agent = <$agent_type>::new()?;

            runtime.run(agent).await
        }
    };
}

#[cfg(test)]
mod tests {
    use super::*;
    use tokio::sync::mpsc;
    use agnos_common::{AgentConfig, AgentId, AgentStatus, Message, MessageType};

    #[test]
    fn test_agent_context_new() {
        let config = AgentConfig::default();
        let (ctx, rx) = AgentContext::new(config);

        assert_eq!(*ctx.status.blocking_read(), AgentStatus::Starting);
        // Receiver is returned separately, not stored in context
        drop(rx);
    }

    #[test]
    fn test_agent_runtime_new() {
        let config = AgentConfig::default();
        let _runtime = AgentRuntime::new(config);
        // Runtime should be created without panicking
    }

    #[tokio::test]
    async fn test_agent_context_send_message() {
        let config = AgentConfig::default();
        let (ctx, rx) = AgentContext::new(config);

        // Drop the receiver so the send will fail
        drop(rx);

        let result = ctx.send_message("target", serde_json::json!({"test": true})).await;
        // This should fail because the receiver has been dropped
        assert!(result.is_err());
    }

    #[tokio::test]
    async fn test_agent_context_status() {
        let config = AgentConfig::default();
        let (ctx, _rx) = AgentContext::new(config);

        ctx.set_status(AgentStatus::Running).await;
        assert_eq!(ctx.status().await, AgentStatus::Running);

        ctx.set_status(AgentStatus::Stopped).await;
        assert_eq!(ctx.status().await, AgentStatus::Stopped);
    }

    #[tokio::test]
    async fn test_llm_gateway_constants() {
        // Verify the gateway address and port are correct
        assert_eq!(helpers::LLM_GATEWAY_ADDR, "http://localhost:8088");
    }
}

//! Linux Audit Subsystem Interface
//!
//! Provides safe Rust bindings for the Linux audit subsystem (netlink socket)
//! and the AGNOS kernel audit module (`/proc/agnos/audit`).
//!
//! On non-Linux platforms, all operations return `SysError::NotSupported`.

use crate::error::{Result, SysError};
use serde::{Deserialize, Serialize};
use std::path::Path;

// Linux netlink/audit constants
#[cfg(target_os = "linux")]
const NETLINK_AUDIT: libc::c_int = 9;

// Audit message types
#[cfg(target_os = "linux")]
const AUDIT_GET: u16 = 1000;
#[cfg(target_os = "linux")]
const AUDIT_SET: u16 = 1001;
#[cfg(target_os = "linux")]
const AUDIT_ADD_RULE: u16 = 1011;
#[cfg(target_os = "linux")]
const AUDIT_DEL_RULE: u16 = 1012;
#[cfg(target_os = "linux")]
const AUDIT_USER: u16 = 1005;

// Custom AGNOS audit syscall number
#[cfg(target_os = "linux")]
const SYS_AGNOS_AUDIT_LOG: libc::c_long = 520;

// Netlink message header size
#[cfg(target_os = "linux")]
const NLMSG_HDRLEN: usize = 16;

/// Handle wrapping a netlink audit socket file descriptor.
#[derive(Debug)]
pub struct AuditHandle {
    /// The netlink socket fd (-1 if using proc-only mode)
    fd: i32,
    /// Configuration used to open this handle
    config: AuditConfig,
}

/// Configuration for opening an audit connection.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AuditConfig {
    /// Use the netlink audit socket (AF_NETLINK, NETLINK_AUDIT)
    pub use_netlink: bool,
    /// Use the AGNOS /proc interface
    pub use_agnos_proc: bool,
    /// Path to the AGNOS proc audit file
    pub proc_path: String,
}

impl Default for AuditConfig {
    fn default() -> Self {
        Self {
            use_netlink: true,
            use_agnos_proc: false,
            proc_path: "/proc/agnos/audit".to_string(),
        }
    }
}

/// Current audit subsystem status (from AUDIT_GET).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AuditStatus {
    /// Whether auditing is enabled (1) or disabled (0)
    pub enabled: u32,
    /// Failure action: 0=silent, 1=printk, 2=panic
    pub failure_action: u32,
    /// PID of the audit daemon (0 if none)
    pub pid: u32,
    /// Maximum number of outstanding audit messages
    pub backlog_limit: u32,
    /// Number of audit messages lost
    pub lost: u32,
    /// Current backlog count
    pub backlog: u32,
}

impl Default for AuditStatus {
    fn default() -> Self {
        Self {
            enabled: 0,
            failure_action: 1,
            pid: 0,
            backlog_limit: 8192,
            lost: 0,
            backlog: 0,
        }
    }
}

/// Type of audit rule.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum AuditRuleType {
    /// Watch file access (equivalent to auditctl -w)
    FileWatch,
    /// Watch syscall invocations (equivalent to auditctl -a)
    SyscallWatch,
}

/// An audit rule to add or delete.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AuditRule {
    /// Type of rule
    pub rule_type: AuditRuleType,
    /// Path to watch (for FileWatch rules)
    pub path: Option<String>,
    /// Syscall number (for SyscallWatch rules)
    pub syscall: Option<u32>,
    /// Key string for filtering audit logs
    pub key: String,
}

impl AuditRule {
    /// Create a file watch rule.
    pub fn file_watch(path: impl Into<String>, key: impl Into<String>) -> Self {
        Self {
            rule_type: AuditRuleType::FileWatch,
            path: Some(path.into()),
            syscall: None,
            key: key.into(),
        }
    }

    /// Create a syscall watch rule.
    pub fn syscall_watch(syscall: u32, key: impl Into<String>) -> Self {
        Self {
            rule_type: AuditRuleType::SyscallWatch,
            path: None,
            syscall: Some(syscall),
            key: key.into(),
        }
    }

    /// Validate that the rule is well-formed.
    pub fn validate(&self) -> Result<()> {
        if self.key.is_empty() {
            return Err(SysError::InvalidArgument("Audit rule key cannot be empty".into()));
        }
        if self.key.len() > 256 {
            return Err(SysError::InvalidArgument("Audit rule key too long (max 256)".into()));
        }
        match self.rule_type {
            AuditRuleType::FileWatch => {
                if self.path.is_none() {
                    return Err(SysError::InvalidArgument(
                        "FileWatch rule requires a path".into(),
                    ));
                }
                let path = self.path.as_ref().unwrap();
                if path.is_empty() {
                    return Err(SysError::InvalidArgument(
                        "FileWatch path cannot be empty".into(),
                    ));
                }
                if !path.starts_with('/') {
                    return Err(SysError::InvalidArgument(
                        "FileWatch path must be absolute".into(),
                    ));
                }
            }
            AuditRuleType::SyscallWatch => {
                if self.syscall.is_none() {
                    return Err(SysError::InvalidArgument(
                        "SyscallWatch rule requires a syscall number".into(),
                    ));
                }
            }
        }
        Ok(())
    }
}

/// A raw audit entry from `/proc/agnos/audit`.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RawAuditEntry {
    /// Sequence number
    pub sequence: u64,
    /// Timestamp in nanoseconds since epoch
    pub timestamp_ns: u64,
    /// Type of audit action
    pub action_type: String,
    /// Result code (0 = success)
    pub result: i32,
    /// SHA-256 hash of this entry
    pub hash: String,
    /// SHA-256 hash of the previous entry (empty for first)
    pub prev_hash: String,
    /// Raw payload data
    pub payload: String,
}

/// Open an audit connection based on the given configuration.
///
/// If `use_netlink` is true, opens an `AF_NETLINK` socket with `NETLINK_AUDIT` protocol.
/// Requires `CAP_AUDIT_CONTROL` or root.
///
/// # Errors
/// Returns `SysError::PermissionDenied` if the process lacks capabilities.
/// Returns `SysError::NotSupported` on non-Linux.
pub fn open_audit(config: &AuditConfig) -> Result<AuditHandle> {
    #[cfg(target_os = "linux")]
    {
        let fd = if config.use_netlink {
            let fd = unsafe {
                libc::socket(
                    libc::AF_NETLINK,
                    libc::SOCK_RAW | libc::SOCK_CLOEXEC,
                    NETLINK_AUDIT,
                )
            };
            if fd < 0 {
                let err = std::io::Error::last_os_error();
                return match err.raw_os_error() {
                    Some(libc::EPERM) | Some(libc::EACCES) => Err(SysError::PermissionDenied),
                    Some(libc::EPROTONOSUPPORT) => Err(SysError::NotSupported),
                    _ => Err(SysError::Unknown(format!("socket(NETLINK_AUDIT) failed: {}", err))),
                };
            }

            // Bind the socket
            let mut addr: libc::sockaddr_nl = unsafe { std::mem::zeroed() };
            addr.nl_family = libc::AF_NETLINK as u16;
            addr.nl_pid = unsafe { libc::getpid() } as u32;
            addr.nl_groups = 0;

            let ret = unsafe {
                libc::bind(
                    fd,
                    &addr as *const libc::sockaddr_nl as *const libc::sockaddr,
                    std::mem::size_of::<libc::sockaddr_nl>() as libc::socklen_t,
                )
            };

            if ret < 0 {
                let err = std::io::Error::last_os_error();
                unsafe { libc::close(fd); }
                return Err(SysError::Unknown(format!("bind(NETLINK_AUDIT) failed: {}", err)));
            }

            tracing::debug!("Opened netlink audit socket (fd={})", fd);
            fd
        } else {
            -1
        };

        // Verify proc path if configured
        if config.use_agnos_proc && !Path::new(&config.proc_path).exists() {
            if fd >= 0 {
                unsafe { libc::close(fd); }
            }
            tracing::warn!("AGNOS proc audit path does not exist: {}", config.proc_path);
        }

        Ok(AuditHandle {
            fd,
            config: config.clone(),
        })
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = config;
        Err(SysError::NotSupported)
    }
}

/// Send an audit user message via the netlink socket.
///
/// Sends an `AUDIT_USER` type message with the given event type string and message payload.
pub fn send_audit_event(handle: &AuditHandle, event_type: &str, message: &str) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        if handle.fd < 0 {
            return Err(SysError::InvalidArgument(
                "Audit handle has no netlink socket".into(),
            ));
        }

        if event_type.is_empty() {
            return Err(SysError::InvalidArgument("Event type cannot be empty".into()));
        }
        if message.len() > 8192 {
            return Err(SysError::InvalidArgument("Audit message too large (max 8192)".into()));
        }

        let payload = format!("op={} {}", event_type, message);
        let payload_bytes = payload.as_bytes();
        let total_len = NLMSG_HDRLEN + payload_bytes.len();

        // Build netlink message header + payload
        let mut buf = vec![0u8; total_len];

        // nlmsghdr: len (u32), type (u16), flags (u16), seq (u32), pid (u32)
        let len_bytes = (total_len as u32).to_ne_bytes();
        buf[0..4].copy_from_slice(&len_bytes);
        let type_bytes = AUDIT_USER.to_ne_bytes();
        buf[4..6].copy_from_slice(&type_bytes);
        // flags = NLM_F_REQUEST (1)
        buf[6..8].copy_from_slice(&1u16.to_ne_bytes());
        // seq = 1
        buf[8..12].copy_from_slice(&1u32.to_ne_bytes());
        // pid
        let pid = unsafe { libc::getpid() } as u32;
        buf[12..16].copy_from_slice(&pid.to_ne_bytes());
        // payload
        buf[NLMSG_HDRLEN..].copy_from_slice(payload_bytes);

        let ret = unsafe {
            libc::send(handle.fd, buf.as_ptr() as *const libc::c_void, total_len, 0)
        };

        if ret < 0 {
            let err = std::io::Error::last_os_error();
            return Err(SysError::Unknown(format!("send(audit event) failed: {}", err)));
        }

        tracing::debug!("Sent audit event: op={} ({} bytes)", event_type, payload_bytes.len());
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (handle, event_type, message);
        Err(SysError::NotSupported)
    }
}

/// Query the current audit subsystem status via AUDIT_GET.
pub fn get_audit_status(handle: &AuditHandle) -> Result<AuditStatus> {
    #[cfg(target_os = "linux")]
    {
        if handle.fd < 0 {
            return Err(SysError::InvalidArgument(
                "Audit handle has no netlink socket".into(),
            ));
        }

        // Build AUDIT_GET request
        let total_len = NLMSG_HDRLEN;
        let mut buf = vec![0u8; total_len];
        buf[0..4].copy_from_slice(&(total_len as u32).to_ne_bytes());
        buf[4..6].copy_from_slice(&AUDIT_GET.to_ne_bytes());
        buf[6..8].copy_from_slice(&1u16.to_ne_bytes()); // NLM_F_REQUEST
        buf[8..12].copy_from_slice(&1u32.to_ne_bytes()); // seq
        let pid = unsafe { libc::getpid() } as u32;
        buf[12..16].copy_from_slice(&pid.to_ne_bytes());

        let ret = unsafe {
            libc::send(handle.fd, buf.as_ptr() as *const libc::c_void, total_len, 0)
        };
        if ret < 0 {
            let err = std::io::Error::last_os_error();
            return Err(SysError::Unknown(format!("send(AUDIT_GET) failed: {}", err)));
        }

        // Read response
        let mut recv_buf = vec![0u8; 4096];
        let n = unsafe {
            libc::recv(
                handle.fd,
                recv_buf.as_mut_ptr() as *mut libc::c_void,
                recv_buf.len(),
                0,
            )
        };

        if n < 0 {
            let err = std::io::Error::last_os_error();
            return Err(SysError::Unknown(format!("recv(AUDIT_GET) failed: {}", err)));
        }

        if (n as usize) < NLMSG_HDRLEN + 24 {
            // Minimum: header + audit_status struct fields we care about
            return Err(SysError::Unknown(
                "AUDIT_GET response too short".into(),
            ));
        }

        // Parse audit_status from the payload after nlmsghdr.
        // struct audit_status layout (simplified, first 6 u32 fields):
        //   u32 mask, u32 enabled, u32 failure, u32 pid, u32 rate_limit, u32 backlog_limit, u32 lost, u32 backlog
        let payload = &recv_buf[NLMSG_HDRLEN..n as usize];
        let read_u32 = |offset: usize| -> u32 {
            if offset + 4 <= payload.len() {
                u32::from_ne_bytes([
                    payload[offset],
                    payload[offset + 1],
                    payload[offset + 2],
                    payload[offset + 3],
                ])
            } else {
                0
            }
        };

        Ok(AuditStatus {
            enabled: read_u32(4),         // offset 4
            failure_action: read_u32(8),  // offset 8
            pid: read_u32(12),            // offset 12
            backlog_limit: read_u32(20),  // offset 20
            lost: read_u32(24),           // offset 24
            backlog: read_u32(28),        // offset 28
        })
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = handle;
        Err(SysError::NotSupported)
    }
}

/// Enable or disable the audit subsystem via AUDIT_SET.
pub fn set_audit_enabled(handle: &AuditHandle, enabled: bool) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        if handle.fd < 0 {
            return Err(SysError::InvalidArgument(
                "Audit handle has no netlink socket".into(),
            ));
        }

        // Build AUDIT_SET message with audit_status payload
        // We set mask=1 (AUDIT_STATUS_ENABLED) and enabled=0/1
        let payload_len = 32; // enough for the audit_status fields
        let total_len = NLMSG_HDRLEN + payload_len;
        let mut buf = vec![0u8; total_len];

        // nlmsghdr
        buf[0..4].copy_from_slice(&(total_len as u32).to_ne_bytes());
        buf[4..6].copy_from_slice(&AUDIT_SET.to_ne_bytes());
        buf[6..8].copy_from_slice(&1u16.to_ne_bytes()); // NLM_F_REQUEST
        buf[8..12].copy_from_slice(&1u32.to_ne_bytes());
        let pid = unsafe { libc::getpid() } as u32;
        buf[12..16].copy_from_slice(&pid.to_ne_bytes());

        // audit_status payload
        // mask = 1 (AUDIT_STATUS_ENABLED)
        buf[NLMSG_HDRLEN..NLMSG_HDRLEN + 4].copy_from_slice(&1u32.to_ne_bytes());
        // enabled
        let val: u32 = if enabled { 1 } else { 0 };
        buf[NLMSG_HDRLEN + 4..NLMSG_HDRLEN + 8].copy_from_slice(&val.to_ne_bytes());

        let ret = unsafe {
            libc::send(handle.fd, buf.as_ptr() as *const libc::c_void, total_len, 0)
        };
        if ret < 0 {
            let err = std::io::Error::last_os_error();
            return Err(SysError::Unknown(format!("send(AUDIT_SET) failed: {}", err)));
        }

        tracing::info!("Audit subsystem {}", if enabled { "enabled" } else { "disabled" });
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (handle, enabled);
        Err(SysError::NotSupported)
    }
}

/// Add an audit rule via AUDIT_ADD_RULE.
pub fn add_audit_rule(handle: &AuditHandle, rule: &AuditRule) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        rule.validate()?;
        send_rule_message(handle, rule, AUDIT_ADD_RULE)?;
        tracing::debug!("Added audit rule: key={}", rule.key);
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (handle, rule);
        Err(SysError::NotSupported)
    }
}

/// Delete an audit rule via AUDIT_DEL_RULE.
pub fn delete_audit_rule(handle: &AuditHandle, rule: &AuditRule) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        rule.validate()?;
        send_rule_message(handle, rule, AUDIT_DEL_RULE)?;
        tracing::debug!("Deleted audit rule: key={}", rule.key);
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (handle, rule);
        Err(SysError::NotSupported)
    }
}

/// Send an AUDIT_ADD_RULE or AUDIT_DEL_RULE message.
#[cfg(target_os = "linux")]
fn send_rule_message(handle: &AuditHandle, rule: &AuditRule, msg_type: u16) -> Result<()> {
    if handle.fd < 0 {
        return Err(SysError::InvalidArgument(
            "Audit handle has no netlink socket".into(),
        ));
    }

    // Serialize the rule as a simple text payload (the kernel audit interface
    // accepts both structured audit_rule_data and text-based specifications).
    let rule_text = match rule.rule_type {
        AuditRuleType::FileWatch => {
            format!(
                "watch={} key={}",
                rule.path.as_deref().unwrap_or(""),
                rule.key
            )
        }
        AuditRuleType::SyscallWatch => {
            format!(
                "syscall={} key={}",
                rule.syscall.unwrap_or(0),
                rule.key
            )
        }
    };

    let payload = rule_text.as_bytes();
    let total_len = NLMSG_HDRLEN + payload.len();
    let mut buf = vec![0u8; total_len];

    buf[0..4].copy_from_slice(&(total_len as u32).to_ne_bytes());
    buf[4..6].copy_from_slice(&msg_type.to_ne_bytes());
    buf[6..8].copy_from_slice(&1u16.to_ne_bytes());
    buf[8..12].copy_from_slice(&1u32.to_ne_bytes());
    let pid = unsafe { libc::getpid() } as u32;
    buf[12..16].copy_from_slice(&pid.to_ne_bytes());
    buf[NLMSG_HDRLEN..].copy_from_slice(payload);

    let ret = unsafe {
        libc::send(handle.fd, buf.as_ptr() as *const libc::c_void, total_len, 0)
    };
    if ret < 0 {
        let err = std::io::Error::last_os_error();
        return Err(SysError::Unknown(format!(
            "send(audit rule msg_type={}) failed: {}",
            msg_type, err
        )));
    }

    Ok(())
}

/// Read audit events from the AGNOS `/proc/agnos/audit` interface.
///
/// Each line in the proc file is a JSON-encoded `RawAuditEntry`.
/// Returns an empty vec if the file does not exist.
pub fn read_agnos_audit_events(proc_path: &str) -> Result<Vec<RawAuditEntry>> {
    let path = Path::new(proc_path);
    if !path.exists() {
        return Ok(Vec::new());
    }

    let contents = std::fs::read_to_string(path)
        .map_err(|e| SysError::Unknown(format!("Failed to read {}: {}", proc_path, e)))?;

    let mut entries = Vec::new();
    for line in contents.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        match serde_json::from_str::<RawAuditEntry>(trimmed) {
            Ok(entry) => entries.push(entry),
            Err(e) => {
                tracing::warn!("Skipping malformed audit entry: {}", e);
            }
        }
    }

    Ok(entries)
}

/// Log an audit event via the AGNOS custom syscall (SYS_AGNOS_AUDIT_LOG = 520).
///
/// This is the fast path for kernel-level audit logging from userspace.
pub fn agnos_audit_log_syscall(action: &str, data: &str, result: i32) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        if action.is_empty() {
            return Err(SysError::InvalidArgument("Audit action cannot be empty".into()));
        }
        if action.len() > 256 {
            return Err(SysError::InvalidArgument("Audit action too long (max 256)".into()));
        }
        if data.len() > 4096 {
            return Err(SysError::InvalidArgument("Audit data too long (max 4096)".into()));
        }

        let action_cstr = std::ffi::CString::new(action)
            .map_err(|_| SysError::InvalidArgument("Action contains null byte".into()))?;
        let data_cstr = std::ffi::CString::new(data)
            .map_err(|_| SysError::InvalidArgument("Data contains null byte".into()))?;

        let ret = unsafe {
            libc::syscall(
                SYS_AGNOS_AUDIT_LOG,
                action_cstr.as_ptr(),
                data_cstr.as_ptr(),
                result as libc::c_int,
            )
        };

        if ret < 0 {
            let err = std::io::Error::last_os_error();
            return match err.raw_os_error() {
                Some(libc::ENOSYS) => Err(SysError::NotSupported),
                Some(libc::EPERM) => Err(SysError::PermissionDenied),
                _ => Err(SysError::Unknown(format!("SYS_AGNOS_AUDIT_LOG failed: {}", err))),
            };
        }

        tracing::debug!("Logged audit syscall: action={}, result={}", action, result);
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (action, data, result);
        Err(SysError::NotSupported)
    }
}

/// Close an audit handle, releasing the netlink socket.
pub fn close_audit(handle: AuditHandle) {
    #[cfg(target_os = "linux")]
    {
        if handle.fd >= 0 {
            unsafe { libc::close(handle.fd); }
            tracing::debug!("Closed audit handle (fd={})", handle.fd);
        }
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = handle;
    }
}

