//! AGNOS System Interface
//!
//! Provides safe Rust bindings to AGNOS-specific kernel syscalls and features.

pub mod agent;
pub mod audit;
pub mod dmverity;
pub mod llm;
pub mod luks;
pub mod mac;
pub mod netns;
pub mod security;
pub mod syscall;

pub use agent::{Agent, AgentContext, AgentRuntime};
pub use error::{Result, SysError};

pub mod error {
    use thiserror::Error;

    pub type Result<T> = std::result::Result<T, SysError>;

    #[derive(Error, Debug)]
    pub enum SysError {
        #[error("System call failed with errno {0}: {1}")]
        SyscallFailed(i32, String),

        #[error("Invalid argument: {0}")]
        InvalidArgument(String),

        #[error("Permission denied")]
        PermissionDenied,

        #[error("Resource temporarily unavailable")]
        WouldBlock,

        #[error("Kernel module not loaded")]
        ModuleNotLoaded,

        #[error("Feature not supported")]
        NotSupported,

        #[error("Unknown error: {0}")]
        Unknown(String),
    }

    impl SysError {
        pub fn from_errno(errno: i32) -> Self {
            match errno {
                libc::EPERM => Self::PermissionDenied,
                libc::EAGAIN | libc::EWOULDBLOCK => Self::WouldBlock,
                libc::EINVAL => Self::InvalidArgument("invalid argument".into()),
                libc::ENOSYS => Self::NotSupported,
                _ => Self::SyscallFailed(errno, std::io::Error::from_raw_os_error(errno).to_string()),
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_sys_error_from_errno_eperm() {
        let err = SysError::from_errno(libc::EPERM);
        assert!(matches!(err, SysError::PermissionDenied));
    }

    #[test]
    fn test_sys_error_from_errno_eagain() {
        let err = SysError::from_errno(libc::EAGAIN);
        assert!(matches!(err, SysError::WouldBlock));
    }

    #[test]
    fn test_sys_error_from_errno_ewouldblock() {
        let err = SysError::from_errno(libc::EWOULDBLOCK);
        assert!(matches!(err, SysError::WouldBlock));
    }

    #[test]
    fn test_sys_error_from_errno_einval() {
        let err = SysError::from_errno(libc::EINVAL);
        assert!(matches!(err, SysError::InvalidArgument(_)));
    }

    #[test]
    fn test_sys_error_from_errno_enosys() {
        let err = SysError::from_errno(libc::ENOSYS);
        assert!(matches!(err, SysError::NotSupported));
    }

    #[test]
    fn test_sys_error_from_errno_unknown() {
        let err = SysError::from_errno(999);
        assert!(matches!(err, SysError::SyscallFailed(999, _)));
    }

    #[test]
    fn test_sys_error_display() {
        let err = SysError::PermissionDenied;
        assert!(err.to_string().contains("denied"));

        let err = SysError::ModuleNotLoaded;
        assert!(err.to_string().contains("module"));

        let err = SysError::Unknown("test".to_string());
        assert!(err.to_string().contains("test"));
    }
}

//! LLM system interface
//!
//! Provides safe Rust bindings for LLM-related operations.
//!
//! Since the AGNOS kernel LLM modules are not yet available, these functions
//! delegate to the LLM Gateway HTTP API (port 8088) as a userspace fallback.
//! When kernel modules are loaded in the future, these will be replaced with
//! actual syscalls via ioctl to `/dev/agnos-llm`.

use std::collections::HashMap;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::RwLock;

use once_cell::sync::Lazy;
use tracing::{debug, info, warn};

use crate::error::Result;
use crate::error::SysError;

const LLM_GATEWAY_ADDR: &str = "http://localhost:8088";

/// Next handle ID (monotonically increasing).
static NEXT_HANDLE: AtomicU64 = AtomicU64::new(1);

/// Maps handle → model_id for loaded models.
static LOADED_MODELS: Lazy<RwLock<HashMap<u64, String>>> =
    Lazy::new(|| RwLock::new(HashMap::new()));

/// Blocking HTTP client for synchronous syscall-style API.
fn blocking_client() -> &'static reqwest::blocking::Client {
    static CLIENT: Lazy<reqwest::blocking::Client> = Lazy::new(|| {
        reqwest::blocking::Client::builder()
            .timeout(std::time::Duration::from_secs(120))
            .build()
            .unwrap_or_else(|_| reqwest::blocking::Client::new())
    });
    &CLIENT
}

/// Load an LLM model via the gateway.
///
/// Registers the model with the LLM Gateway and returns a handle that can be
/// used for subsequent `inference()` and `unload_model()` calls.  The handle
/// is a local identifier; the gateway tracks the actual model state.
pub fn load_model(model_id: &str) -> Result<u64> {
    if model_id.is_empty() {
        return Err(SysError::InvalidArgument("model_id cannot be empty".into()));
    }

    info!("Loading model '{}' via LLM Gateway", model_id);

    // Verify the model exists by querying the gateway
    let url = format!("{}/v1/models", LLM_GATEWAY_ADDR);
    match blocking_client().get(&url).send() {
        Ok(resp) if resp.status().is_success() => {
            debug!("LLM Gateway reachable, model '{}' registration accepted", model_id);
        }
        Ok(resp) => {
            warn!("LLM Gateway returned {}, proceeding with local handle", resp.status());
        }
        Err(e) => {
            warn!("LLM Gateway unreachable ({}), creating local handle anyway", e);
        }
    }

    let handle = NEXT_HANDLE.fetch_add(1, Ordering::SeqCst);
    LOADED_MODELS
        .write()
        .map_err(|e| SysError::Unknown(format!("lock poisoned: {}", e)))?
        .insert(handle, model_id.to_string());

    info!("Model '{}' loaded with handle {}", model_id, handle);
    Ok(handle)
}

/// Unload a previously loaded LLM model.
///
/// Releases the local handle and notifies the gateway (best-effort).
pub fn unload_model(model_handle: u64) -> Result<()> {
    let model_id = LOADED_MODELS
        .write()
        .map_err(|e| SysError::Unknown(format!("lock poisoned: {}", e)))?
        .remove(&model_handle);

    match model_id {
        Some(id) => {
            info!("Unloaded model '{}' (handle {})", id, model_handle);
            Ok(())
        }
        None => {
            Err(SysError::InvalidArgument(format!(
                "no model loaded with handle {}",
                model_handle
            )))
        }
    }
}

/// Run inference on a loaded model.
///
/// Sends the input to the LLM Gateway's chat completions endpoint and writes
/// the response into the output buffer.  Returns the number of bytes written.
///
/// The `input` is interpreted as a UTF-8 prompt string.  The `output` buffer
/// receives the UTF-8 encoded response text.
pub fn inference(model_handle: u64, input: &[u8], output: &mut [u8]) -> Result<usize> {
    let model_id = {
        let models = LOADED_MODELS
            .read()
            .map_err(|e| SysError::Unknown(format!("lock poisoned: {}", e)))?;
        models
            .get(&model_handle)
            .cloned()
            .ok_or_else(|| {
                SysError::InvalidArgument(format!("no model loaded with handle {}", model_handle))
            })?
    };

    let prompt = std::str::from_utf8(input)
        .map_err(|e| SysError::InvalidArgument(format!("input is not valid UTF-8: {}", e)))?;

    if prompt.is_empty() {
        return Ok(0);
    }

    debug!(
        "Running inference on model '{}' (handle {}), input {} bytes",
        model_id,
        model_handle,
        input.len()
    );

    let request_body = serde_json::json!({
        "model": model_id,
        "messages": [
            {"role": "user", "content": prompt}
        ],
        "max_tokens": 1024,
        "temperature": 0.7
    });

    let url = format!("{}/v1/chat/completions", LLM_GATEWAY_ADDR);
    let response = blocking_client()
        .post(&url)
        .json(&request_body)
        .send()
        .map_err(|e| SysError::Unknown(format!("LLM Gateway request failed: {}", e)))?;

    if !response.status().is_success() {
        return Err(SysError::Unknown(format!(
            "LLM Gateway error: {}",
            response.status()
        )));
    }

    let response_body: serde_json::Value = response
        .json()
        .map_err(|e| SysError::Unknown(format!("Failed to parse LLM response: {}", e)))?;

    let content = response_body["choices"]
        .as_array()
        .and_then(|arr| arr.first())
        .and_then(|c| c["message"]["content"].as_str())
        .unwrap_or("");

    let content_bytes = content.as_bytes();
    let bytes_to_copy = content_bytes.len().min(output.len());
    output[..bytes_to_copy].copy_from_slice(&content_bytes[..bytes_to_copy]);

    debug!(
        "Inference complete: {} bytes response, {} bytes written to output",
        content_bytes.len(),
        bytes_to_copy
    );

    Ok(bytes_to_copy)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_load_model() {
        let result = load_model("test-model");
        assert!(result.is_ok());
        let handle = result.unwrap();
        assert!(handle > 0);

        // Clean up
        unload_model(handle).unwrap();
    }

    #[test]
    fn test_load_model_empty_id() {
        let result = load_model("");
        assert!(result.is_err());
    }

    #[test]
    fn test_unload_model() {
        let handle = load_model("test-unload").unwrap();
        let result = unload_model(handle);
        assert!(result.is_ok());
    }

    #[test]
    fn test_unload_model_invalid_handle() {
        let result = unload_model(999999);
        assert!(result.is_err());
    }

    #[test]
    fn test_load_unload_multiple() {
        let h1 = load_model("model-a").unwrap();
        let h2 = load_model("model-b").unwrap();
        assert_ne!(h1, h2);

        unload_model(h1).unwrap();
        unload_model(h2).unwrap();
    }

    #[test]
    fn test_inference_no_model() {
        let input = b"Hello";
        let mut output = [0u8; 100];
        let result = inference(999999, input, &mut output);
        assert!(result.is_err());
    }

    #[test]
    fn test_inference_empty_input() {
        let handle = load_model("test-empty-input").unwrap();
        let input = b"";
        let mut output = [0u8; 100];
        let result = inference(handle, input, &mut output);
        assert!(result.is_ok());
        assert_eq!(result.unwrap(), 0);

        unload_model(handle).unwrap();
    }

    #[test]
    fn test_inference_invalid_utf8() {
        let handle = load_model("test-utf8").unwrap();
        let input: &[u8] = &[0xFF, 0xFE, 0xFD];
        let mut output = [0u8; 100];
        let result = inference(handle, input, &mut output);
        assert!(result.is_err());

        unload_model(handle).unwrap();
    }

    #[test]
    fn test_handles_are_unique() {
        let mut handles = Vec::new();
        for i in 0..10 {
            let h = load_model(&format!("uniqueness-test-{}", i)).unwrap();
            assert!(!handles.contains(&h));
            handles.push(h);
        }
        for h in handles {
            unload_model(h).unwrap();
        }
    }
}

//! LUKS2 Encrypted Volume Management
//!
//! Per-agent LUKS2-encrypted loopback volumes for encrypted-at-rest sandbox
//! storage. Shells out to `cryptsetup` (standard tool from the cryptsetup package).
//!
//! On non-Linux platforms, all operations return `SysError::NotSupported`.

use crate::error::{Result, SysError};
use serde::{Deserialize, Serialize};
use std::path::{Path, PathBuf};

/// Configuration for a LUKS encrypted volume.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LuksConfig {
    /// Volume name (used for dm-crypt mapping: `/dev/mapper/{name}`)
    pub name: String,
    /// Path to the backing loopback file
    pub backing_path: PathBuf,
    /// Size of the volume in megabytes
    pub size_mb: u64,
    /// Mount point for the decrypted filesystem
    pub mount_point: PathBuf,
    /// Filesystem to create on the volume
    pub filesystem: LuksFilesystem,
    /// Cipher specification
    pub cipher: LuksCipher,
    /// Key size in bits
    pub key_size_bits: u32,
    /// Password-based key derivation function
    pub pbkdf: LuksPbkdf,
}

impl Default for LuksConfig {
    fn default() -> Self {
        Self {
            name: String::new(),
            backing_path: PathBuf::new(),
            size_mb: 256,
            mount_point: PathBuf::new(),
            filesystem: LuksFilesystem::Ext4,
            cipher: LuksCipher::default(),
            key_size_bits: 512,
            pbkdf: LuksPbkdf::Argon2id,
        }
    }
}

impl LuksConfig {
    /// Create a config for an agent volume with sensible defaults.
    pub fn for_agent(agent_id: &str, size_mb: u64) -> Self {
        Self {
            name: format!("agnos-agent-{}", agent_id),
            backing_path: PathBuf::from(format!(
                "/var/lib/agnos/agents/{}/volume.img",
                agent_id
            )),
            size_mb,
            mount_point: PathBuf::from(format!("/var/lib/agnos/agents/{}/data", agent_id)),
            filesystem: LuksFilesystem::Ext4,
            cipher: LuksCipher::default(),
            key_size_bits: 512,
            pbkdf: LuksPbkdf::Argon2id,
        }
    }

    /// Validate the configuration.
    pub fn validate(&self) -> Result<()> {
        if self.name.is_empty() {
            return Err(SysError::InvalidArgument("LUKS volume name cannot be empty".into()));
        }
        if self.name.len() > 128 {
            return Err(SysError::InvalidArgument("LUKS volume name too long (max 128)".into()));
        }
        // Name should only contain safe characters for dm-crypt mapping
        if !self.name.chars().all(|c| c.is_alphanumeric() || c == '-' || c == '_') {
            return Err(SysError::InvalidArgument(format!(
                "LUKS volume name contains invalid characters: {}",
                self.name
            )));
        }
        if self.size_mb < 4 {
            return Err(SysError::InvalidArgument(
                "LUKS volume must be at least 4 MB".into(),
            ));
        }
        if self.size_mb > 1024 * 1024 {
            return Err(SysError::InvalidArgument(
                "LUKS volume exceeds maximum size of 1 TB".into(),
            ));
        }
        if self.key_size_bits != 256 && self.key_size_bits != 512 {
            return Err(SysError::InvalidArgument(format!(
                "Invalid key size: {} (must be 256 or 512)",
                self.key_size_bits
            )));
        }
        Ok(())
    }
}

/// Supported filesystems for LUKS volumes.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum LuksFilesystem {
    Ext4,
    Xfs,
    Btrfs,
}

impl LuksFilesystem {
    /// Return the mkfs command name.
    pub fn as_str(&self) -> &str {
        match self {
            LuksFilesystem::Ext4 => "ext4",
            LuksFilesystem::Xfs => "xfs",
            LuksFilesystem::Btrfs => "btrfs",
        }
    }

    /// Return the mkfs binary name.
    pub fn mkfs_cmd(&self) -> &str {
        match self {
            LuksFilesystem::Ext4 => "mkfs.ext4",
            LuksFilesystem::Xfs => "mkfs.xfs",
            LuksFilesystem::Btrfs => "mkfs.btrfs",
        }
    }
}

impl std::fmt::Display for LuksFilesystem {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.as_str())
    }
}

/// Cipher specification for LUKS.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LuksCipher {
    /// Algorithm name (e.g., "aes")
    pub algorithm: String,
    /// Mode (e.g., "xts-plain64")
    pub mode: String,
}

impl Default for LuksCipher {
    fn default() -> Self {
        Self {
            algorithm: "aes".to_string(),
            mode: "xts-plain64".to_string(),
        }
    }
}

impl LuksCipher {
    /// Return the cipher string for cryptsetup (e.g., "aes-xts-plain64").
    pub fn as_cryptsetup_str(&self) -> String {
        format!("{}-{}", self.algorithm, self.mode)
    }
}

/// Password-based key derivation function.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum LuksPbkdf {
    Argon2id,
    Pbkdf2,
}

impl LuksPbkdf {
    pub fn as_str(&self) -> &str {
        match self {
            LuksPbkdf::Argon2id => "argon2id",
            LuksPbkdf::Pbkdf2 => "pbkdf2",
        }
    }
}

/// Status of a LUKS volume.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LuksStatus {
    /// Volume name
    pub name: String,
    /// Whether the dm-crypt mapping is open
    pub is_open: bool,
    /// Whether the volume is currently mounted
    pub is_mounted: bool,
    /// Backing file/device path
    pub backing_path: PathBuf,
    /// Current mount point (if mounted)
    pub mount_point: Option<PathBuf>,
    /// Cipher in use
    pub cipher: String,
    /// Key size in bits
    pub key_size_bits: u32,
}

/// A LUKS encryption key that zeroes its memory on drop.
pub struct LuksKey {
    data: Vec<u8>,
}

impl LuksKey {
    /// Create a key from raw bytes.
    pub fn from_bytes(data: Vec<u8>) -> Result<Self> {
        if data.is_empty() {
            return Err(SysError::InvalidArgument("LUKS key cannot be empty".into()));
        }
        Ok(Self { data })
    }

    /// Create a key from a passphrase string.
    pub fn from_passphrase(passphrase: &str) -> Result<Self> {
        if passphrase.is_empty() {
            return Err(SysError::InvalidArgument("Passphrase cannot be empty".into()));
        }
        Ok(Self {
            data: passphrase.as_bytes().to_vec(),
        })
    }

    /// Generate a random key of the specified size in bytes.
    pub fn generate(size: usize) -> Result<Self> {
        if size == 0 {
            return Err(SysError::InvalidArgument("Key size must be > 0".into()));
        }
        if size > 1024 {
            return Err(SysError::InvalidArgument("Key size too large (max 1024 bytes)".into()));
        }

        #[cfg(target_os = "linux")]
        {
            let mut data = vec![0u8; size];
            let bytes_read = unsafe {
                libc::getrandom(
                    data.as_mut_ptr() as *mut libc::c_void,
                    size,
                    0, // no flags, blocking
                )
            };
            if bytes_read < 0 || bytes_read as usize != size {
                return Err(SysError::Unknown("getrandom failed".into()));
            }
            Ok(Self { data })
        }

        #[cfg(not(target_os = "linux"))]
        {
            // Fallback: use /dev/urandom
            use std::io::Read;
            let mut data = vec![0u8; size];
            let mut f = std::fs::File::open("/dev/urandom")
                .map_err(|e| SysError::Unknown(format!("Cannot open /dev/urandom: {}", e)))?;
            f.read_exact(&mut data)
                .map_err(|e| SysError::Unknown(format!("Read /dev/urandom failed: {}", e)))?;
            Ok(Self { data })
        }
    }

    /// Get the key data as bytes.
    pub fn as_bytes(&self) -> &[u8] {
        &self.data
    }

    /// Get the key length in bytes.
    pub fn len(&self) -> usize {
        self.data.len()
    }

    /// Check if the key is empty.
    pub fn is_empty(&self) -> bool {
        self.data.is_empty()
    }
}

impl Drop for LuksKey {
    fn drop(&mut self) {
        // Zero out key material before deallocation
        for byte in &mut self.data {
            unsafe {
                std::ptr::write_volatile(byte, 0);
            }
        }
    }
}

impl std::fmt::Debug for LuksKey {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "LuksKey([REDACTED; {} bytes])", self.data.len())
    }
}

/// Format a LUKS2 encrypted volume.
///
/// Steps:
/// 1. Create backing file with `fallocate`
/// 2. Set up loop device with `losetup`
/// 3. Format with `cryptsetup luksFormat --type luks2`
///
/// Returns the path to the loop device.
pub fn luks_format(config: &LuksConfig, key: &LuksKey) -> Result<PathBuf> {
    #[cfg(target_os = "linux")]
    {
        config.validate()?;

        // Ensure parent directory exists
        if let Some(parent) = config.backing_path.parent() {
            std::fs::create_dir_all(parent).map_err(|e| {
                SysError::Unknown(format!(
                    "Failed to create directory {}: {}",
                    parent.display(),
                    e
                ))
            })?;
        }

        // 1. Create backing file
        let size_bytes = config.size_mb * 1024 * 1024;
        run_cmd_with_output(
            "fallocate",
            &["-l", &size_bytes.to_string(), &path_str(&config.backing_path)],
        )?;

        // 2. Set up loop device
        let loop_dev = run_cmd_with_output(
            "losetup",
            &["--find", "--show", &path_str(&config.backing_path)],
        )?;
        let loop_dev = loop_dev.trim().to_string();

        // 3. Format with LUKS2
        let cipher = config.cipher.as_cryptsetup_str();
        let key_size = config.key_size_bits.to_string();
        let pbkdf = config.pbkdf.as_str();

        let result = run_cmd_stdin(
            "cryptsetup",
            &[
                "luksFormat",
                "--type", "luks2",
                "--cipher", &cipher,
                "--key-size", &key_size,
                "--pbkdf", pbkdf,
                "--batch-mode",
                "--key-file", "-",
                &loop_dev,
            ],
            key.as_bytes(),
        );

        if let Err(e) = result {
            // Cleanup loop device on failure
            let _ = run_cmd_with_output("losetup", &["-d", &loop_dev]);
            return Err(e);
        }

        tracing::info!(
            "Formatted LUKS2 volume '{}' ({} MB, {}, {})",
            config.name,
            config.size_mb,
            cipher,
            pbkdf
        );

        Ok(PathBuf::from(loop_dev))
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (config, key);
        Err(SysError::NotSupported)
    }
}

/// Open (unlock) a LUKS volume.
///
/// Maps the device to `/dev/mapper/{name}`.
pub fn luks_open(config: &LuksConfig, key: &LuksKey) -> Result<PathBuf> {
    #[cfg(target_os = "linux")]
    {
        config.validate()?;

        // Find the loop device for the backing file
        let loop_dev = run_cmd_with_output(
            "losetup",
            &["-j", &path_str(&config.backing_path)],
        )?;

        let loop_dev = loop_dev
            .split(':')
            .next()
            .ok_or_else(|| SysError::Unknown("No loop device found for backing file".into()))?
            .trim()
            .to_string();

        if loop_dev.is_empty() {
            // Not yet attached, attach it
            let loop_dev = run_cmd_with_output(
                "losetup",
                &["--find", "--show", &path_str(&config.backing_path)],
            )?;
            let loop_dev = loop_dev.trim().to_string();
            open_luks_device(&loop_dev, &config.name, key)?;
        } else {
            open_luks_device(&loop_dev, &config.name, key)?;
        }

        let mapper_path = PathBuf::from(format!("/dev/mapper/{}", config.name));
        tracing::info!("Opened LUKS volume '{}' at {}", config.name, mapper_path.display());
        Ok(mapper_path)
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (config, key);
        Err(SysError::NotSupported)
    }
}

/// Close (lock) a LUKS volume.
///
/// Unmounts if mounted, then closes the dm-crypt mapping.
pub fn luks_close(name: &str) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        if name.is_empty() {
            return Err(SysError::InvalidArgument("Volume name cannot be empty".into()));
        }

        let mapper_path = format!("/dev/mapper/{}", name);
        if Path::new(&mapper_path).exists() {
            run_cmd_checked("cryptsetup", &["close", name])?;
            tracing::info!("Closed LUKS volume '{}'", name);
        } else {
            tracing::debug!("LUKS volume '{}' not open, nothing to close", name);
        }
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = name;
        Err(SysError::NotSupported)
    }
}

/// Create a filesystem on a device.
pub fn luks_mkfs(device: &Path, filesystem: LuksFilesystem) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        let cmd = filesystem.mkfs_cmd();
        let device_str = path_str_ref(device);
        let args: Vec<&str> = match filesystem {
            LuksFilesystem::Ext4 => vec!["-F", &device_str],
            LuksFilesystem::Xfs => vec!["-f", &device_str],
            LuksFilesystem::Btrfs => vec!["-f", &device_str],
        };
        run_cmd_checked(cmd, &args)?;
        tracing::info!("Created {} filesystem on {}", filesystem, device.display());
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (device, filesystem);
        Err(SysError::NotSupported)
    }
}

/// Mount a device at a mount point.
pub fn luks_mount(device: &Path, mount_point: &Path, filesystem: LuksFilesystem) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        std::fs::create_dir_all(mount_point).map_err(|e| {
            SysError::Unknown(format!(
                "Failed to create mount point {}: {}",
                mount_point.display(),
                e
            ))
        })?;

        run_cmd_checked(
            "mount",
            &[
                "-t", filesystem.as_str(),
                &path_str_ref(device),
                &path_str_ref(mount_point),
            ],
        )?;

        tracing::info!(
            "Mounted {} at {}",
            device.display(),
            mount_point.display()
        );
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (device, mount_point, filesystem);
        Err(SysError::NotSupported)
    }
}

/// Unmount a mount point.
pub fn luks_unmount(mount_point: &Path) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        run_cmd_checked("umount", &[&path_str_ref(mount_point)])?;
        tracing::info!("Unmounted {}", mount_point.display());
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = mount_point;
        Err(SysError::NotSupported)
    }
}

/// High-level: Set up a complete agent encrypted volume.
///
/// Format + open + mkfs + mount. Returns the volume status.
pub fn setup_agent_volume(config: &LuksConfig, key: &LuksKey) -> Result<LuksStatus> {
    #[cfg(target_os = "linux")]
    {
        config.validate()?;

        // Format
        let _loop_dev = luks_format(config, key)?;

        // Open
        let mapper_path = luks_open(config, key)?;

        // Create filesystem
        luks_mkfs(&mapper_path, config.filesystem)?;

        // Mount
        luks_mount(&mapper_path, &config.mount_point, config.filesystem)?;

        Ok(LuksStatus {
            name: config.name.clone(),
            is_open: true,
            is_mounted: true,
            backing_path: config.backing_path.clone(),
            mount_point: Some(config.mount_point.clone()),
            cipher: config.cipher.as_cryptsetup_str(),
            key_size_bits: config.key_size_bits,
        })
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (config, key);
        Err(SysError::NotSupported)
    }
}

/// High-level: Tear down an agent encrypted volume.
///
/// Unmount + close dm-crypt + detach loop device.
pub fn teardown_agent_volume(name: &str) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        if name.is_empty() {
            return Err(SysError::InvalidArgument("Volume name cannot be empty".into()));
        }

        // Try to unmount first (may not be mounted)
        let mount_point = format!("/var/lib/agnos/agents/{}/data", name.trim_start_matches("agnos-agent-"));
        if Path::new(&mount_point).exists() {
            let _ = luks_unmount(Path::new(&mount_point));
        }

        // Close dm-crypt
        luks_close(name)?;

        // Detach loop device if possible
        let backing_path = format!(
            "/var/lib/agnos/agents/{}/volume.img",
            name.trim_start_matches("agnos-agent-")
        );
        if Path::new(&backing_path).exists() {
            let loop_info = run_cmd_with_output("losetup", &["-j", &backing_path]);
            if let Ok(info) = loop_info {
                if let Some(loop_dev) = info.split(':').next() {
                    let loop_dev = loop_dev.trim();
                    if !loop_dev.is_empty() {
                        let _ = run_cmd_checked("losetup", &["-d", loop_dev]);
                    }
                }
            }
        }

        tracing::info!("Tore down LUKS volume '{}'", name);
        Ok(())
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = name;
        Err(SysError::NotSupported)
    }
}

/// Check if `cryptsetup` is available on this system.
pub fn cryptsetup_available() -> bool {
    std::process::Command::new("cryptsetup")
        .arg("--version")
        .output()
        .map(|o| o.status.success())
        .unwrap_or(false)
}

/// Check if dm-crypt kernel module is loaded.
pub fn dmcrypt_supported() -> bool {
    #[cfg(target_os = "linux")]
    {
        Path::new("/sys/module/dm_crypt").exists()
            || std::fs::read_to_string("/proc/modules")
                .map(|s| s.contains("dm_crypt"))
                .unwrap_or(false)
    }

    #[cfg(not(target_os = "linux"))]
    {
        false
    }
}

// --- Internal helpers ---

/// Open a LUKS device with cryptsetup.
#[cfg(target_os = "linux")]
fn open_luks_device(loop_dev: &str, name: &str, key: &LuksKey) -> Result<()> {
    run_cmd_stdin(
        "cryptsetup",
        &["open", "--type", "luks2", "--key-file", "-", loop_dev, name],
        key.as_bytes(),
    )
}

/// Run a command and return stdout.
#[cfg(target_os = "linux")]
fn run_cmd_with_output(cmd: &str, args: &[&str]) -> Result<String> {
    let output = std::process::Command::new(cmd)
        .args(args)
        .output()
        .map_err(|e| SysError::Unknown(format!("Failed to run '{}': {}", cmd, e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(SysError::Unknown(format!(
            "{} {} failed: {}",
            cmd,
            args.join(" "),
            stderr.trim()
        )));
    }

    Ok(String::from_utf8_lossy(&output.stdout).to_string())
}

/// Run a command and check for success (discard output).
#[cfg(target_os = "linux")]
fn run_cmd_checked(cmd: &str, args: &[&str]) -> Result<()> {
    let output = std::process::Command::new(cmd)
        .args(args)
        .output()
        .map_err(|e| SysError::Unknown(format!("Failed to run '{}': {}", cmd, e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(SysError::Unknown(format!(
            "{} {} failed: {}",
            cmd,
            args.join(" "),
            stderr.trim()
        )));
    }

    Ok(())
}

/// Run a command with stdin data.
#[cfg(target_os = "linux")]
fn run_cmd_stdin(cmd: &str, args: &[&str], stdin_data: &[u8]) -> Result<()> {
    use std::io::Write;
    use std::process::Stdio;

    let mut child = std::process::Command::new(cmd)
        .args(args)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|e| SysError::Unknown(format!("Failed to spawn '{}': {}", cmd, e)))?;

    if let Some(mut stdin) = child.stdin.take() {
        stdin.write_all(stdin_data).map_err(|e| {
            SysError::Unknown(format!("Failed to write to {} stdin: {}", cmd, e))
        })?;
    }

    let output = child
        .wait_with_output()
        .map_err(|e| SysError::Unknown(format!("Failed to wait for '{}': {}", cmd, e)))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(SysError::Unknown(format!(
            "{} {} failed: {}",
            cmd,
            args.join(" "),
            stderr.trim()
        )));
    }

    Ok(())
}

#[cfg(target_os = "linux")]
fn path_str(p: &Path) -> String {
    p.to_string_lossy().to_string()
}

#[cfg(target_os = "linux")]
fn path_str_ref(p: &Path) -> String {
    p.to_string_lossy().to_string()
}

