        assert_eq!(cmd, "ls");
        assert_eq!(args, vec!["-la"]);
    }

    #[test]
    fn test_split_command_with_quotes() {
        let result = split_command("echo \"hello world\"");
        assert!(result.is_ok());
        let (cmd, args) = result.unwrap();
