//! AGNOS AI Shell (agnsh)
//!
//! A natural language shell interface with built-in human oversight.
//! Never exposes root to AI - all privileged operations require human approval.

use anyhow::Result;
use clap::Parser;
use std::path::PathBuf;
use tracing::{info, warn};

mod approval;
pub mod audit;
pub mod commands;
pub mod config;
pub mod history;
pub mod interpreter;
pub mod llm;
pub mod mode;
pub mod output;
pub mod permissions;
pub mod prompt;
pub mod sandbox;
pub mod security;
pub mod session;
pub mod ui;

use approval::ApprovalManager;
use config::ShellConfig;
use mode::{Mode, ModeManager};
use security::SecurityContext;
use session::Session;

#[derive(Parser, Debug)]
#[command(name = "agnsh")]
#[command(about = "AGNOS AI Shell - Natural language interface with human oversight")]
#[command(version)]
struct Args {
    /// Start in AI mode
    #[arg(short, long)]
    ai: bool,

    /// Start in human mode (default)
    #[arg(short, long)]
    human: bool,

    /// Execute command and exit
    #[arg(short, long)]
    command: Option<String>,

    /// Configuration file path
    #[arg(short, long)]
    config: Option<PathBuf>,

    /// Disable AI assistance
    #[arg(long)]
    no_ai: bool,

    /// Require approval for all AI actions
    #[arg(long)]
    strict: bool,

    /// Start as restricted user (no privilege escalation)
    #[arg(long)]
    restricted: bool,

    /// Use starship-style prompt
    #[arg(long)]
    starship: bool,

    /// Custom prompt format (starship-style)
    #[arg(long)]
    prompt_format: Option<String>,
}

#[tokio::main]
async fn main() -> Result<()> {
    // Initialize logging
    tracing_subscriber::fmt::init();

    let args = Args::parse();

    // Load configuration
    let config = if let Some(config_path) = args.config {
        ShellConfig::from_file(config_path).await?
    } else {
        ShellConfig::default()
    };

    // Initialize security context
    let security = SecurityContext::new(args.restricted)?;

    info!("Starting AGNOS AI Shell v{}", env!("CARGO_PKG_VERSION"));
    info!("User: {}, Restricted: {}", security.username(), security.is_restricted());

    // Determine initial mode
    let initial_mode = if args.ai {
        Mode::AiAutonomous
    } else if args.human {
        Mode::Human
    } else {
        config.default_mode.clone()
    };

    // Create session
    let mut session = Session::new(config, security, initial_mode).await?;

    // Handle one-shot command execution
    if let Some(cmd) = args.command {
        session.execute_one_shot(cmd).await?;
        return Ok(());
    }

    // Run interactive shell
    session.run_interactive().await?;

    Ok(())
}

//! Shell mode management
//!
//! Controls whether the shell is in AI autonomous mode,
//! human mode, or collaborative mode.

use anyhow::Result;
use serde::{Deserialize, Serialize};
use std::fmt;

/// Shell operating modes
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum Mode {
    /// AI acts autonomously within constraints
    AiAutonomous,
    /// AI assists human user
    AiAssisted,
    /// Human user in control
    Human,
    /// Strict mode - all actions require approval
    Strict,
}

impl Default for Mode {
    fn default() -> Self {
        Mode::AiAssisted
    }
}

impl fmt::Display for Mode {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Mode::AiAutonomous => write!(f, "AI-AUTO"),
            Mode::AiAssisted => write!(f, "AI-ASSIST"),
            Mode::Human => write!(f, "HUMAN"),
            Mode::Strict => write!(f, "STRICT"),
        }
    }
}

impl Mode {
    /// Check if AI is allowed to execute commands autonomously
    pub fn ai_autonomous(&self) -> bool {
        matches!(self, Mode::AiAutonomous)
    }

    /// Check if AI assistance is available
    pub fn ai_available(&self) -> bool {
        !matches!(self, Mode::Human)
    }

    /// Check if strict approval is required
    pub fn strict_approval(&self) -> bool {
        matches!(self, Mode::Strict)
    }

    /// Get description of mode
    pub fn description(&self) -> &'static str {
        match self {
            Mode::AiAutonomous => "AI acts autonomously within safety constraints",
            Mode::AiAssisted => "AI assists human with suggestions and explanations",
            Mode::Human => "Human user has full control, no AI assistance",
            Mode::Strict => "All actions require explicit human approval",
        }
    }

    /// Get prompt prefix for this mode
    pub fn prompt_prefix(&self) -> &'static str {
        match self {
            Mode::AiAutonomous => "🤖",
            Mode::AiAssisted => "👤🤖",
            Mode::Human => "👤",
            Mode::Strict => "🔒",
        }
    }
}

/// Mode manager for tracking and switching modes
pub struct ModeManager {
    current: Mode,
    previous: Option<Mode>,
    allow_switching: bool,
}

impl ModeManager {
    pub fn new(initial: Mode, allow_switching: bool) -> Self {
        Self {
            current: initial,
            previous: None,
            allow_switching,
        }
    }

    /// Get current mode
    pub fn current(&self) -> &Mode {
        &self.current
    }

    /// Switch to a new mode
    pub fn switch(&mut self, mode: Mode) -> Result<()> {
        if !self.allow_switching && self.current != mode {
            return Err(anyhow::anyhow!("Mode switching is disabled"));
        }

        self.previous = Some(self.current.clone());
        self.current = mode;

        Ok(())
    }

    /// Switch back to previous mode
    pub fn revert(&mut self) -> Result<()> {
        if let Some(prev) = self.previous.take() {
            self.current = prev;
            Ok(())
        } else {
            Err(anyhow::anyhow!("No previous mode to revert to"))
        }
    }

    /// Toggle between AI and human modes
    pub fn toggle(&mut self) {
        let new_mode = match self.current {
            Mode::Human => Mode::AiAssisted,
            Mode::AiAssisted => Mode::Human,
            Mode::AiAutonomous => Mode::Human,
            Mode::Strict => Mode::AiAssisted,
        };

        self.previous = Some(self.current.clone());
        self.current = new_mode;
    }

    /// List all available modes
    pub fn available_modes(&self) -> Vec<Mode> {
        vec![
            Mode::Human,
            Mode::AiAssisted,
            Mode::AiAutonomous,
            Mode::Strict,
        ]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_mode_switching() {
        let mut manager = ModeManager::new(Mode::Human, true);

        assert_eq!(manager.current(), &Mode::Human);

        manager.switch(Mode::AiAssisted).unwrap();
        assert_eq!(manager.current(), &Mode::AiAssisted);

        manager.revert().unwrap();
        assert_eq!(manager.current(), &Mode::Human);
    }

    #[test]
    fn test_ai_permissions() {
        assert!(Mode::AiAutonomous.ai_autonomous());
        assert!(!Mode::AiAssisted.ai_autonomous());
        assert!(!Mode::Human.ai_autonomous());
        assert!(!Mode::Strict.ai_autonomous());
    }
}

//! Output formatting

pub struct OutputFormatter {
    format: String,
}

impl OutputFormatter {
    pub fn new(format: &str) -> Self {
        Self {
            format: format.to_string(),
        }
    }

    /// Format command output
    pub fn format(&self, output: &str) -> String {
        match self.format.as_str() {
            "json" => self.format_json(output),
            "table" => self.format_table(output),
            "auto" => self.format_auto(output),
            _ => output.to_string(),
        }
    }

    fn format_json(&self, output: &str) -> String {
        serde_json::json!({"output": output}).to_string()
    }

    fn format_table(&self, output: &str) -> String {
        // Detect if output looks like a table
        if output.contains('\t') || output.contains("  ") {
            // Attempt to format as table
            output.to_string()
        } else {
            output.to_string()
        }
    }

    fn format_auto(&self, output: &str) -> String {
        // Auto-detect format based on content
        output.to_string()
    }
}

impl Default for OutputFormatter {
    fn default() -> Self {
        Self::new("auto")
    }
}

